// Atomic reference counting (RISC-V + LoongArch compatible)
static inline void refcnt_inc(int *p) {
  __sync_fetch_and_add(p, 1);
}

// Returns new value. 0 means last reference dropped.
static inline int refcnt_dec(int *p) {
  return __sync_sub_and_fetch(p, 1);
}

