#include "types.h"
#include "param.h"
#include "memlayout.h"
#include "arch.h"
#include "defs.h"

extern pagetable_t kernel_pagetable;
volatile static int started = 0;

// start() jumps here in supervisor mode on all CPUs.
void
main()
{
  if(cpuid() == 0){
    consoleinit();
    printfinit();
    printf("\n");
    printf("xv6 kernel is booting\n");
#ifdef __loongarch__
#endif
    kinit();         // physical page allocator
    slab_init();     // slab allocator (must be after kinit)
    kvminit();       // create kernel page table
    proc_mapstacks(kernel_pagetable);  // map kernel stacks (needs kalloc)
    kvminithart();   // turn on paging
    procinit();      // process table
    trapinit();      // trap vectors
    trapinithart();  // install kernel trap vector
    plicinit();      // set up interrupt controller
    plicinithart();  // ask PLIC for device interrupts
    binit();         // buffer cache
    vfs_init();     // VFS + inode table
    fileinit();      // file table
    futex_init();    // futex subsystem
  shm_init();      // shared memory
    virtio_disk_init(0); // emulated hard disk (required)
    if (virtio_disk_init(1) < 0)  // second disk (optional, may not exist)
      printf("virtio_disk_init1: not found, continuing\n");
    // net_init();      // network subsystem (disabled for testing)
    userinit();      // first user process
    __sync_synchronize();
    started = 1;
  } else {
    while(started == 0)
      ;
    __sync_synchronize();
    kvminithart();    // turn on paging
    trapinithart();   // install kernel trap vector
    plicinithart();   // ask PLIC for device interrupts
  }

  // On RISC-V, set the first timer interrupt before entering scheduler.
  // On LoongArch, the timer is started in forkret() just before the first
  // return to user mode, so interrupts are enabled via ertn immediately after.
#if defined(__loongarch__)
  timerinit();
#else
  sbi_set_timer(r_time() + 1000000);
#endif
  scheduler();
}

