#include "types.h"
#include "param.h"
#include "memlayout.h"
#include "arch.h"
#include "spinlock.h"
#include "proc.h"
#include "defs.h"
#include "file.h"
#include "kernel/vfs/vfs.h"
#include "kernel/errno.h"
#include "futex.h"

struct cpu cpus[NCPU];

struct proc proc[NPROC];

struct proc *initproc;

int nextpid = 1;
struct spinlock pid_lock;

extern void forkret(void);
static void freeproc(struct proc *p);

extern char trampoline[]; // trampoline.S

// helps ensure that wakeups of wait()ing
// parents are not lost. helps obey the
// memory model when using p->parent.
// must be acquired before any p->lock.
struct spinlock wait_lock;

// Allocate KSTACK_PAGES for each process's kernel stack.
// On LoongArch, uses identity mapping (VA=PA) for DMW0 compatibility.
// On RISC-V, maps virtual KSTACK(pid) to physical pages from kalloc.
void
proc_mapstacks(pagetable_t kpgtbl)
{
  struct proc *p;

  for(p = proc; p < &proc[NPROC]; p++) {
    uint64 va = KSTACK((int) (p - proc));
    for(int i = 0; i < KSTACK_PAGES + 1; i++) {
      uint64 addr = va + i*PGSIZE;
      char *pa = kalloc();
      if(pa == 0)
        panic("proc_mapstacks: kalloc");
#ifdef __loongarch__
      // LoongArch: identity map VA=PA for DMW0 compatibility.
      // kstack addresses (KSTACK_BASE=0x80A00000) are in physical RAM.
      (void)pa;  // page reserved from free pool
      kvmmap(kpgtbl, addr, addr, PGSIZE,
             PTE_R | PTE_W | PTE_MAT_CC | PTE_G);
#else
      // RISC-V: map VA to the allocated physical page.
      // KSTACK virtual addresses are near MAXVA, not in physical RAM.
      kvmmap(kpgtbl, addr, (uint64)pa, PGSIZE,
             PTE_R | PTE_W);
#endif
    }
  }
}

// initialize the proc table.
void
procinit(void)
{
  struct proc *p;

  initlock(&pid_lock, "nextpid");
  initlock(&wait_lock, "wait_lock");
  for(p = proc; p < &proc[NPROC]; p++) {
      initlock(&p->lock, "proc");
      p->state = UNUSED;
      p->kstack = KSTACK((int) (p - proc));
  }
}

// Must be called with interrupts disabled,
// to prevent race with process being moved
// to a different CPU.
int
cpuid()
{
  int id = r_tp();
  return id;
}

// Return this CPU's cpu struct.
// Interrupts must be disabled.
struct cpu*
mycpu(void)
{
  int id = cpuid();
  struct cpu *c = &cpus[id];
  return c;
}

// Return the current struct proc *, or zero if none.
struct proc*
myproc(void)
{
  push_off();
  struct cpu *c = mycpu();
  struct proc *p = c->proc;
  pop_off();
  return p;
}

int
allocpid()
{
  int pid;

  acquire(&pid_lock);
  pid = nextpid;
  nextpid = nextpid + 1;
  release(&pid_lock);

  return pid;
}

// Look in the process table for an UNUSED proc.
// If found, initialize state required to run in the kernel,
// and return with p->lock held.
// If there are no free procs, or a memory allocation fails, return 0.
static struct proc*
allocproc(void)
{
  struct proc *p;

  for(p = proc; p < &proc[NPROC]; p++) {
    acquire(&p->lock);
    if(p->state == UNUSED) {
      goto found;
    } else {
      release(&p->lock);
    }
  }
  return 0;

found:
  p->pid = allocpid();
  p->state = USED;
  p->tgid = p->pid;  // default: thread group leader is self
  p->pgid = p->pid;  // default: process group leader is self

  // Allocate a trapframe page.
  if((p->trapframe = (struct trapframe *)kalloc()) == 0){
    freeproc(p);
    release(&p->lock);
    return 0;
  }
  memset(p->trapframe, 0, PGSIZE);

  // Allocate per-process signal_struct.
  signal_init(p);

  // filetable already allocated by Task 4
  p->ft = filetable_alloc();
  if(p->ft == 0){
    freeproc(p);
    release(&p->lock);
    return 0;
  }

  // mm and pagetable are allocated by kfork/kclone (not allocproc)
  p->mm = 0;

  // Set up new context to start executing at forkret,
  // which returns to user space.
#ifdef __loongarch__
  // On LoongArch, we use _forkret_asm (in swtch.S) as the entry point
  // because the toolchain may not correctly encode $sp operations in C.
  extern void _forkret_asm(void);
#endif
  memset(&p->context, 0, sizeof(p->context));
#ifdef __loongarch__
  p->context.ra = (uint64)_forkret_asm;
#else
  p->context.ra = (uint64)forkret;
#endif
