// Allocate 2^order contiguous physical pages from zone z.
// Returns physical address, or 0 on failure.
void *
alloc_pages(struct zone *z, int order)
{
  int o;
  struct page *page;

  if (order < 0 || order >= MAX_ORDER)
    return 0;

  acquire(&z->lock);

  // Search upward for a free block of sufficient order
  for (o = order; o < MAX_ORDER; o++) {
    if (z->free_area[o].nr_free > 0) {
      // Pop first page from free list
      page = list_entry(z->free_area[o].free_list.next, struct page, lru);
      list_del(&page->lru);
      ClearPageBuddy(page);
      z->free_area[o].nr_free--;

      // Split down to requested order
      while (o > order) {
        o--;
        struct page *buddy_page = page + (1 << o);
        buddy_page->order = o;
        SetPageBuddy(buddy_page);
        list_add(&buddy_page->lru, &z->free_area[o].free_list);
        z->free_area[o].nr_free++;
      }

      page->order = order;
      page->refcount = 1;

      // Poison BEFORE release to close PTE residual race:
      // If timer interrupt fires between release() and memset(),
      // another process can get this page with stale data (0x01 poison
      // instead of 0x05). Old PTE values (e.g. 0xfffffffc7fffffff)
      // on reused user stack pages cause ret to jump to garbage addresses.
      memset((void *)page_to_pa(page), 5, PGSIZE << order);
      release(&z->lock);
      return (void *)page_to_pa(page);
    }
  }

  release(&z->lock);
  return 0;  // out of memory
}

