// Name buffers for kmalloc caches (static to avoid dynamic allocation)
static char kmalloc_names[KMALLOC_CACHES][16];

// Dedicated caches for high-frequency structs
struct kmem_cache *vma_cachep;
struct kmem_cache *mm_cachep;
struct kmem_cache *lwext4_inode_cachep;
struct kmem_cache *xv6_inode_cachep;
struct kmem_cache *file_cachep;

// Allocate a new slab page from buddy and initialize its freelist.
// Returns 0 on success, -1 on failure.
static int
slab_grow(struct kmem_cache *cache)
{
  void *pa = alloc_pages(get_zone_normal(), 0);
  if (!pa)
    return -1;

  struct page *page = pa_to_page((uint64)pa);

  // Calculate how many objects fit in one page
  uint32 objects = PGSIZE / cache->obj_size;
  if (objects == 0)
    panic("slab_grow: obj_size too large");

  // Build embedded freelist: each free object's first 8 bytes point to next
  void *freelist = 0;
  for (int i = objects - 1; i >= 0; i--) {
    void *obj = (char *)pa + i * cache->obj_size;
    *(void **)obj = freelist;
    freelist = obj;
  }

  // Set struct page slab fields
  SetPageSlab(page);
  page->inuse = 0;
  page->objects = objects;
  page->freelist = freelist;
  page->cache = cache;

  // Add to cache's slabs_partial list (new page has all objects free)
  list_add(&page->lru, &cache->slabs_partial);

  return 0;
}

struct kmem_cache *
kmem_cache_create(const char *name, uint32 size)
{
  struct kmem_cache *cache;

  // Dynamic creation via kalloc is safe since slab_init runs after kinit.
  cache = (struct kmem_cache *)kalloc();
  if (!cache)
    return 0;

  memset(cache, 0, sizeof(*cache));
  cache->name = name;

  // Object size: at least 8 bytes (for freelist pointer), 8-byte aligned
  cache->obj_size = size;
  if (cache->obj_size < sizeof(void *))
    cache->obj_size = sizeof(void *);
  cache->obj_size = (cache->obj_size + 7) & ~7;  // align to 8

  INIT_LIST_HEAD(&cache->slabs_partial);
  INIT_LIST_HEAD(&cache->slabs_full);
  initlock(&cache->lock, "slab");

  return cache;
}

void
kmem_cache_destroy(struct kmem_cache *cache)
{
  // Step A: empty implementation.
  // The predefined kmalloc caches are never destroyed.
  // Step B: free all slab pages back to buddy.
  (void)cache;
}

void *
kmem_cache_alloc(struct kmem_cache *cache)
{
  struct page *page;
  void *obj;

  acquire(&cache->lock);

  // 1. Try partial list (has free objects)
  if (!list_empty(&cache->slabs_partial)) {
    page = list_entry(cache->slabs_partial.next, struct page, lru);
  }
  // 2. Grow: allocate a new slab page
  else {
    if (slab_grow(cache) < 0) {
      release(&cache->lock);
      return 0;  // OOM
    }
    page = list_entry(cache->slabs_partial.next, struct page, lru);
  }

  // 3. Pop object from freelist
  obj = page->freelist;
  page->freelist = *(void **)obj;
  page->inuse++;

  // Zero the object to match lwext4_mem.c behavior.
  memset(obj, 0, cache->obj_size);

  // 4. If page is now full, move to full list
  if (page->inuse == page->objects) {
    list_del(&page->lru);
    list_add(&page->lru, &cache->slabs_full);
  }

  release(&cache->lock);
  return obj;
}

void
kmem_cache_free(struct kmem_cache *cache, void *obj)
{
  struct page *page;

  page = pa_to_page((uint64)obj);

  acquire(&cache->lock);

  int was_full = (page->inuse == page->objects);

  // 1. Push object back to freelist
  *(void **)obj = page->freelist;
  page->freelist = obj;
  page->inuse--;

  // 2. If page was full, move to partial
  if (was_full) {
    list_del(&page->lru);
    list_add(&page->lru, &cache->slabs_partial);
  }

  // 3. If page is now empty, return to buddy
  if (page->inuse == 0) {
    list_del(&page->lru);
    ClearPageSlab(page);
    page->freelist = 0;
    page->cache = 0;
    free_pages(pa_to_zone(page_to_pa(page)),
               (void *)page_to_pa(page), 0);
  }

  release(&cache->lock);
}

void *
kmalloc(uint64 size)
{
  if (size == 0)
    return 0;

  // Route to appropriate kmalloc cache
  for (int i = 0; i < KMALLOC_CACHES; i++) {
    if (size <= kmalloc_sizes[i])
      return kmem_cache_alloc(&kmalloc_caches[i]);
  }

  // Large allocation: go directly to buddy
  uint32 pages = ((uint32)size + PGSIZE - 1) / PGSIZE;
  int order = 0;
  while ((1 << order) < pages)
    order++;

  void *pa = alloc_pages(get_zone_normal(), order);
  if (pa) {
    // Record order in struct page so kfree can free the right amount
    struct page *page = pa_to_page((uint64)pa);
    page->order = order;
  }
  return pa;
}

void *
kcalloc(uint64 nmemb, uint64 size)
{
  if (size != 0 && nmemb > (uint64)-1 / size)
    return 0;  // overflow
  uint64 total = nmemb * size;
  void *p = kmalloc(total);
  if (p)
    memset(p, 0, total);
  return p;
}

void
kfree(void *ptr)
{
  struct page *page;

  if (!ptr)
    return;

  page = pa_to_page((uint64)ptr);

  if (PageSlab(page)) {
    // Slab object: route to its cache
    kmem_cache_free(page->cache, ptr);
  } else {
    // Large allocation: return directly to buddy
    free_pages(pa_to_zone((uint64)ptr), ptr, page->order);
  }
}

void
slab_init(void)
{
  for (int i = 0; i < KMALLOC_CACHES; i++) {
    // Build name: "kmalloc-16", "kmalloc-32", etc.
    snprintf(kmalloc_names[i], sizeof(kmalloc_names[i]),
             "kmalloc-%u", kmalloc_sizes[i]);

    struct kmem_cache *c = &kmalloc_caches[i];
    c->name = kmalloc_names[i];

    // Object size: at least 8, aligned to 8
    c->obj_size = kmalloc_sizes[i];
    if (c->obj_size < sizeof(void *))
      c->obj_size = sizeof(void *);
    c->obj_size = (c->obj_size + 7) & ~7;

    INIT_LIST_HEAD(&c->slabs_partial);
    INIT_LIST_HEAD(&c->slabs_full);
    initlock(&c->lock, (char *)c->name);
  }

  // Dedicated caches for high-frequency structs
  vma_cachep = kmem_cache_create("vma", sizeof(struct vma));
  if (!vma_cachep) panic("slab_init: vma_cachep");
  mm_cachep  = kmem_cache_create("mm_struct", sizeof(struct mm_struct));
  if (!mm_cachep) panic("slab_init: mm_cachep");

  // Dedicated inode caches per filesystem
  lwext4_inode_cachep = kmem_cache_create("lwext4_inode", sizeof(struct lwext4_inode_info));
  if (!lwext4_inode_cachep) panic("slab_init: lwext4_inode_cachep");
  xv6_inode_cachep    = kmem_cache_create("xv6_inode", sizeof(struct xv6_inode_info));
  if (!xv6_inode_cachep) panic("slab_init: xv6_inode_cachep");
  file_cachep         = kmem_cache_create("file", sizeof(struct file));
  if (!file_cachep) panic("slab_init: file_cachep");
}

