// inode operations

// vfs层iget，逻辑与xv6中类似，不过缓存使用inode指针数组不是inode数组
struct inode *iget(uint dev, uint inum, struct super_block *sb){
    struct inode *ip;
    int empty = -1;

    acquire(&itable.lock);

    // 找缓存中是否已经存在
    for(int i = 0; i < VFS_NINODE; i++){
        ip = itable.ips[i];
        if(ip && ip->ref > 0 && ip->dev == dev && ip->inum == inum){
            ip->ref++;
            release(&itable.lock);
            return ip;
        }
        if(empty == -1 && (ip == 0 || ip->ref == 0)){
            empty = i;
        }
    }

    // 没有空位，暂时panic，可优化
    if(empty == -1){
        panic("iget: no inodes");
    }

    // 先给新的inode分配内存
    ip = sb->s_op->alloc_inode(sb);
    initsleeplock(&ip->lock, "inode");
    ip->dev = dev;
    ip->inum = inum;
    ip->ref = 1;
    ip->valid = 0;
    ip->i_sb = sb;
    ip->atime = 0;
    ip->mtime = 0;
    ip->ctime = 0;

    // 写入缓存
    itable.ips[empty] = ip;
    release(&itable.lock);
    return ip;
}

// vfs层idup，与xv6逻辑相同，但当valid为0时调用i_op中的fill_from_disk填充inode字段
struct inode *idup(struct inode *ip){
    acquire(&itable.lock);
    ip->ref++;
    release(&itable.lock);
    return ip;
}

// similar to xv6
void ilock(struct inode *ip){
    if(ip == 0 || ip->ref < 1){
        panic("ilock");
    }

    acquiresleep(&ip->lock);
    if(ip->valid == 0){
        ip->i_sb->s_op->read_inode(ip);
        ip->valid = 1;
        if(ip->type == 0){
            panic("ilock: no type");
        }
    }
}

// same as xv6
void iunlock(struct inode *ip){
    if(ip == 0 || !holdingsleep(&ip->lock) || ip->ref < 1){
        // WARN instead of panic — allows tests to continue
        struct proc *p = myproc();
        printf("WARNING: iunlock bad ip=%p ref=%d caller=%s(%d) lock_held_by=%d locked=%d\n",
               ip, ip ? ip->ref : -1,
               p ? p->name : "?", p ? p->pid : -1,
               ip ? ip->lock.pid : -1,
               ip ? ip->lock.locked : 0);
        return;
    }

    releasesleep(&ip->lock);
}

// similar to xv6
void iput(struct inode *ip){
    acquire(&itable.lock);

    if(ip->ref == 1 && ip->valid && ip->nlink == 0){
        acquiresleep(&ip->lock);

        // 从itable中删除，避免悬空指针
        for(int i=0;i<VFS_NINODE;i++){
            if(itable.ips[i] == ip){
                itable.ips[i]=0;
                break;
            }
        }

        release(&itable.lock);

        // 确认该函数可用
        if(ip->i_sb->s_op->evict_inode){
            // 从磁盘中清除
            ip->i_sb->s_op->evict_inode(ip);
        }


        releasesleep(&ip->lock);    // 先释放锁再释放内存
        // 释放内存
        ip->i_sb->s_op->destroy_inode(ip->i_sb, ip);
        return ;
    }
    ip->ref--;
    release(&itable.lock);
}

// same as xv6
void iunlockput(struct inode *ip){
    iunlock(ip);
    iput(ip);
}

// mount

// 找根目录对应的inode
struct inode *find_mount_root(char *path){
    return idup(&stub_root);
}

// 检查当前目录是否是挂载点，是则返回被挂载的fs的根节点inode
struct inode *check_mount(struct inode *ip){
    struct inode *ret = 0;
    acquire(&mount_table.lock);
    for(int i = 0; i< MAX_MOUNTS; i++){
        if(mount_table.mounts[i].used && 
           mount_table.mounts[i].mountpoint == ip){
            ret = mount_table.mounts[i].sb->s_root;
            break;
        }
    }
    release(&mount_table.lock);
    if(ret){
        return idup(ret);
    }
    return ret;
}

// path resolution

// same as xv6
int namecmp(const char *s, const char *t)
{
  return strncmp(s, t, VFS_NAME_LEN);
}

// same as xv6
static char *skipelem(char *path, char *name){
    char *s;
    int len;

    while(*path == '/')
        path++;
    if(*path == 0)
        return 0;
    s = path;
    while(*path != '/' && *path != 0)
        path++;
    len = path - s;
    if(len >= VFS_NAME_LEN)
        memmove(name, s, VFS_NAME_LEN);
    else {
        memmove(name, s, len);
        name[len] = 0;
    }
    while(*path == '/')
        path++;
    return path;
}

// 相较于xv6增加一个inode指针参数，用于openat从指定dir开始解析路径
// start为0时跟xv6原namex功能相同，start不为0时从start(调用者需要确认start为dir)开始解析路径
// 返回的inode指针已增加引用
static struct inode *namex(struct inode *start, char *path, int nameiparent, char *name){
    struct inode *ip, *next;

    if(start){      // start不为空，从start开始解析路径
        ip = idup(start);       // start可能是挂载目录
    }else if(*path == '/'){
        ip = find_mount_root(path);
    }else{
        ip = idup(myproc()->cwd);
    }
    struct inode *mount_root = check_mount(ip);
    if(mount_root){
        iput(ip);
        ip = mount_root;
    }

    while((path = skipelem(path, name)) != 0){
        ilock(ip);
        if(ip->type != T_DIR){
            iunlockput(ip);
            return 0;
        }
        if(nameiparent && *path == '\0'){
            iunlock(ip);
            return ip;
        }

        // Handle "." (current directory) -- skip lookup entirely
        if(name[0] == '.' && name[1] == '\0'){
            iunlock(ip);
            continue;
        }

        next = ip->i_op->lookup(ip, name);  // vfs lookup
        iunlock(ip);
        if(next == 0){
            iput(ip);
            return 0;
        }

        // Symlink resolution: follow symlinks (up to 8 levels)
        {
          int symlink_depth = 0;
          while(next && next->type == T_SYMLINK && symlink_depth < 8){
            char target[MAXPATH];
            ilock(next);
            int r = 0;
            if(next->i_op->readlink)
              r = next->i_op->readlink(next, target, sizeof(target));
            iunlock(next);
            if(r <= 0){
              iput(next);
              iput(ip);
              return 0;
            }
            target[r] = '\0';
            iput(next);

            // Resolve target: if absolute, start from root;
            // if relative, resolve relative to current directory (ip)
            struct inode *resolved;
            if(target[0] == '/'){
              resolved = namex(0, target, 0, name);
            } else {
              resolved = namex(ip, target, 0, name);
            }
            if(resolved == 0){
              iput(ip);
              return 0;
            }
            next = resolved;
            symlink_depth++;
          }

          if(symlink_depth >= 8){
            iput(next);
            iput(ip);
            return 0;
          }
        }

        mount_root = check_mount(next);
        if(mount_root){
            iput(next);
            ip = mount_root;
        }else{
            ip = next;
        }
    }
    if(nameiparent){
        iput(ip);
        return 0;
    }
    return ip;
}

// same as xv6
struct inode *namei(char *path){
    char name[VFS_NAME_LEN];
    return namex(0, path, 0, name);
}

// same as xv6
struct inode *nameiparent(char *path, char *name){
    return namex(0, path,  1, name);
}

