/* ---- 默认信号行为 ---- */

static int signal_default_ignore(int sig) {
  switch (sig) {
    case SIGCHLD:
    case SIGCONT:
    case SIGURG:
    case SIGWINCH:
      return 1;
    default:
      return 0;
  }
}

static int signal_default_terminate(int sig) {
  switch (sig) {
    case SIGCHLD:
    case SIGCONT:
    case SIGURG:
    case SIGWINCH:
    case SIGSTOP:
    case SIGTSTP:
    case SIGTTIN:
    case SIGTTOU:
      return 0;
    default:
      return 1;
  }
}

/* ---- 信号生命周期管理 ---- */

void signal_init(struct proc *p) {
  // Allocate shared signal_struct
  p->signal = (struct signal_struct*)kalloc();
  if(p->signal == 0)
    panic("signal_init: kalloc");
  memset(p->signal, 0, PGSIZE);
  initlock(&p->signal->lock, "signal");
  p->signal->refcnt = 1;

  // Per-thread fields
  p->sigpending = 0;
  p->sigblocked = 0;
  p->sig_old_blocked = 0;
}

void signal_copy(struct proc *parent, struct proc *child) {
  // Share signal_struct (CLONE_SIGHAND semantics)
  child->signal = parent->signal;
  refcnt_inc(&parent->signal->refcnt);

  // Per-thread fields are independent
  child->sigpending = 0;
  child->sigblocked = parent->sigblocked;
  child->sig_old_blocked = 0;
}

struct signal_struct*
signal_struct_copy(struct signal_struct *src)
{
  struct signal_struct *sig = (struct signal_struct*)kalloc();
  if(sig == 0)
    return 0;
  memset(sig, 0, PGSIZE);
  initlock(&sig->lock, "signal");
  sig->refcnt = 1;

  // Deep copy signal handlers
  memcpy(sig->sighand, src->sighand, sizeof(src->sighand));
  memcpy(sig->sa_flags, src->sa_flags, sizeof(src->sa_flags));
  memcpy(sig->sa_mask, src->sa_mask, sizeof(src->sa_mask));
  memcpy(sig->sa_restorer, src->sa_restorer, sizeof(src->sa_restorer));
  sig->alarm_ticks = src->alarm_ticks;
  sig->alarm_handler = src->alarm_handler;

  return sig;
}

void
signal_struct_put(struct signal_struct *sig)
{
  if(refcnt_dec(&sig->refcnt) == 0) {
    kfree_page((void*)sig);
  }
}

void signal_reset_on_exec(struct proc *p) {
  // Reset shared signal handlers to defaults
  memset(p->signal->sighand, 0, sizeof(p->signal->sighand));
  memset(p->signal->sa_flags, 0, sizeof(p->signal->sa_flags));
  memset(p->signal->sa_mask, 0, sizeof(p->signal->sa_mask));
  memset(p->signal->sa_restorer, 0, sizeof(p->signal->sa_restorer));
  p->signal->alarm_ticks = 0;
  p->signal->alarm_handler = 0;
  p->sigpending = 0;
  // sigblocked is NOT cleared on exec
}

/* ---- 信号发送 ---- */

int signal_send(struct proc *target, int sig) {
  if (sig <= 0 || sig >= NSIG) return -EINVAL;

  acquire(&target->lock);
  // Guard: signal struct may already be freed during exit (kexit frees
  // signal before setting state=ZOMBIE, creating a race window).
  if (target->signal == 0 || target->state == ZOMBIE) {
    release(&target->lock);
    return 0;
  }
  acquire(&target->signal->lock);
  uintptr_t handler = target->signal->sighand[sig-1];
  release(&target->signal->lock);

  if (handler == (uintptr_t)SIG_IGN) {
    release(&target->lock);
    return 0;
  }

  target->sigpending |= signal_mask_bit(sig);

  // SIGCANCEL (33): wake the target so it can trap and let do_signal
  // deliver the cancel_handler. Do NOT set killed — the handler
  // must run in userspace to call pthread_exit(PTHREAD_CANCELED).
  // Blocking syscalls check sigpending directly and return -EINTR,
  // which causes usertrap → do_signal → handler → pthread_exit.

  // Save wakeup info before releasing lock to avoid deadlock with wakeup()
  int need_wakeup = (target->state == SLEEPING);
  void *chan = target->chan;

  release(&target->lock);

  if (need_wakeup)
    wakeup(chan);

  return 0;
}

