  p->sigblocked |= p->signal->sa_mask[sig-1];
  if (!(p->signal->sa_flags[sig-1] & SA_NODEFER))
    p->sigblocked |= signal_mask_bit(sig);

  // SA_RESETHAND: reset handler to SIG_DFL after first invocation
  if (p->signal->sa_flags[sig-1] & SA_RESETHAND) {
    acquire(&p->signal->lock);
    p->signal->sighand[sig-1] = (uintptr_t)SIG_DFL;
    p->signal->sa_flags[sig-1] = 0;
    p->signal->sa_restorer[sig-1] = 0;
    p->signal->sa_mask[sig-1] = 0;
    release(&p->signal->lock);
