  sc->sc_regs[1]  = p->trapframe->ra;
  sc->sc_regs[2]  = p->trapframe->sp;
  sc->sc_regs[3]  = p->trapframe->gp;
  sc->sc_regs[4]  = p->trapframe->tp;
