  sc->sc_regs[6]  = p->trapframe->t1;
  sc->sc_regs[7]  = p->trapframe->t2;
  sc->sc_regs[8]  = p->trapframe->s0;
  sc->sc_regs[9]  = p->trapframe->s1;
  sc->sc_regs[10] = p->trapframe->a0;
  sc->sc_regs[11] = p->trapframe->a1;
  sc->sc_regs[12] = p->trapframe->a2;
  sc->sc_regs[13] = p->trapframe->a3;
  sc->sc_regs[14] = p->trapframe->a4;
  sc->sc_regs[15] = p->trapframe->a5;
  sc->sc_regs[16] = p->trapframe->a6;
  sc->sc_regs[17] = p->trapframe->a7;
