// futex — userspace fast synchronization primitive
// Physical address hashing for correct cross-process futex on shared memory.

#include "types.h"
#include "param.h"
#include "arch.h"
#include "defs.h"
#include "spinlock.h"
#include "proc.h"
#include "vm.h"
#include "futex.h"
#include "errno.h"

struct futex_bucket futex_table[FUTEX_BUCKETS];

void
futex_init(void)
{
  for(int i = 0; i < FUTEX_BUCKETS; i++) {
    initlock(&futex_table[i].lock, "futex");
    futex_table[i].waiters = 0;
  }
}

// Translate user VA to PA via page table walk.
// Returns 0 if the page is not mapped.
static uint64
futex_pa(pagetable_t pt, uint64 va)
{
  pte_t *pte = walk(pt, va, 0);
  if(pte == 0 || (*pte & PTE_V) == 0)
    return 0;
  return PTE2PA(*pte) | (va & 0xFFF);
}

// Hash PA to bucket.
static struct futex_bucket*
futex_bucket_from_pa(uint64 pa)
{
  return &futex_table[(pa >> 12) % FUTEX_BUCKETS];
}

// Remove all waiters belonging to proc p from all futex buckets.
// Called from freeproc() to prevent use-after-free on the process's
// kernel stack which holds stack-local futex_waiter structs.
void
futex_cleanup_proc(struct proc *p)
{
  for(int i = 0; i < FUTEX_BUCKETS; i++) {
    struct futex_bucket *b = &futex_table[i];
    acquire(&b->lock);
    struct futex_waiter **pp = &b->waiters;
    while(*pp) {
      if((*pp)->proc == p) {
        *pp = (*pp)->next;
      } else {
        pp = &(*pp)->next;
      }
    }
    release(&b->lock);
  }
}

// Wake a single sleeping process. Caller must NOT hold b->lock
// (to avoid deadlock with futex_wait's lock ordering).
static void
futex_wakeup_proc(struct proc *p)
{
  acquire(&p->lock);
  if(p->state == SLEEPING)
    p->state = RUNNABLE;
  release(&p->lock);
}

// FUTEX_WAIT / FUTEX_WAIT_BITSET: sleep if *addr == val.
int
futex_wait(uint64 addr, uint32_t val, uint64 bitset)
{
  struct proc *p = myproc();
  uint32_t cur;

  if(p->mm == 0 || p->mm->pagetable == 0)
    return -EFAULT;

  // Read current value from user space.
  if(copyin(p->mm->pagetable, (char*)&cur, addr, sizeof(uint32_t)) < 0)
    return -EFAULT;

  // Value mismatch: return immediately (Linux semantics).
  if(cur != val)
    return -EAGAIN;

  uint64 pa = futex_pa(p->mm->pagetable, addr);
  if(pa == 0)
    return -EFAULT;

  struct futex_bucket *b = futex_bucket_from_pa(pa);
  struct futex_waiter w;
  w.proc = p;
  w.pa = pa;
  w.bitset = bitset;

  // Add waiter to bucket list, then sleep.
  // Lock ordering: bucket lock -> p->lock (briefly) -> release bucket lock -> sched().
  acquire(&b->lock);
  w.next = b->waiters;
  b->waiters = &w;

  acquire(&p->lock);
  p->state = SLEEPING;
  release(&b->lock);

  // Set p->chan so signal-delivery wakeup can find us.
  // Same pattern as sleep() in proc.c.
  p->chan = (void*)b;
  sched();

  // Woken up (by futex_wake, signal, or kill).
  // Clean up waiter from bucket list if still present.
  p->chan = 0;
  release(&p->lock);
  acquire(&b->lock);
  struct futex_waiter **pp = &b->waiters;
  while(*pp) {
    if(*pp == &w) {
      *pp = w.next;
      break;
    }
    pp = &(*pp)->next;
  }
  release(&b->lock);

  // Thread was killed while sleeping — return EINTR.
  if(killed(p))
    return -EINTR;

  // Signal arrived while sleeping — let userspace cancel check run.
  if(p->sigpending & ~p->sigblocked)
    return -EINTR;

  return 0;
}

// FUTEX_WAKE: wake up to 'count' waiters sleeping on addr.
int
futex_wake(uint64 addr, int count, uint64 bitset)
{
  struct proc *p = myproc();
  if(p->mm == 0 || p->mm->pagetable == 0)
    return -EFAULT;
  uint64 pa = futex_pa(p->mm->pagetable, addr);
  if(pa == 0)
    return -EFAULT;

  struct futex_bucket *b = futex_bucket_from_pa(pa);
  int woken = 0;

  // Phase 1: collect waiters to wake (under bucket lock).
  acquire(&b->lock);
  struct futex_waiter **pp = &b->waiters;
  while(*pp && woken < count) {
    struct futex_waiter *w = *pp;
    if(w->pa == pa && (w->bitset & bitset)) {
      // Remove from list while holding bucket lock.
      *pp = w->next;
      woken++;
      // Wake process outside bucket lock to avoid deadlock.
      release(&b->lock);
      futex_wakeup_proc(w->proc);
      acquire(&b->lock);
      // pp still points at the correct next pointer.
    } else {
      pp = &(*pp)->next;
    }
  }
  release(&b->lock);

  return woken;
}

// FUTEX_REQUEUE: wake 'count' waiters on uaddr, then requeue up to
// 'count2' remaining waiters from uaddr to uaddr2. No value check.
int
futex_requeue(uint64 uaddr, int count, uint64 uaddr2, int count2)
{
  struct proc *p = myproc();

  if(p->mm == 0 || p->mm->pagetable == 0)
    return -EFAULT;

  uint64 pa1 = futex_pa(p->mm->pagetable, uaddr);
  uint64 pa2 = futex_pa(p->mm->pagetable, uaddr2);
  if(pa1 == 0 || pa2 == 0)
    return -EFAULT;

  struct futex_bucket *b1 = futex_bucket_from_pa(pa1);
  int woken = 0, requeued = 0;

  // Phase 1: wake up to 'count' waiters from b1.
  acquire(&b1->lock);
  struct futex_waiter **pp = &b1->waiters;
  while(*pp && woken < count) {
    struct futex_waiter *w = *pp;
    if(w->pa == pa1) {
      *pp = w->next;
      woken++;
      release(&b1->lock);
      futex_wakeup_proc(w->proc);
      acquire(&b1->lock);
    } else {
      pp = &(*pp)->next;
    }
  }

  // Phase 2: requeue remaining waiters from b1 to b2.
  release(&b1->lock);

  if(count2 > 0) {
    struct futex_bucket *b2 = futex_bucket_from_pa(pa2);
    acquire(&b2->lock);
    acquire(&b1->lock);
    pp = &b1->waiters;
    while(*pp && requeued < count2) {
      struct futex_waiter *w = *pp;
      if(w->pa == pa1) {
        *pp = w->next;
        w->pa = pa2;
        w->next = b2->waiters;
        b2->waiters = w;
        requeued++;
      } else {
        pp = &(*pp)->next;
      }
    }
    release(&b1->lock);
    release(&b2->lock);
  }

  return woken + requeued;
}

// FUTEX_CMP_REQUEUE: wake 'count' waiters on uaddr, then requeue up to
// 'count2' remaining waiters from uaddr to uaddr2.
// Returns total woken + requeued.
int
futex_cmp_requeue(uint64 uaddr, uint32_t expected,
                  uint64 uaddr2, int count, int count2)
{
  struct proc *p = myproc();
  uint32_t cur;

  if(p->mm == 0 || p->mm->pagetable == 0)
    return -EFAULT;

  if(copyin(p->mm->pagetable, (char*)&cur, uaddr, sizeof(uint32_t)) < 0)
    return -EFAULT;
  if(cur != expected)
    return -EAGAIN;

  uint64 pa1 = futex_pa(p->mm->pagetable, uaddr);
  uint64 pa2 = futex_pa(p->mm->pagetable, uaddr2);
  if(pa1 == 0 || pa2 == 0)
    return -EFAULT;

  struct futex_bucket *b1 = futex_bucket_from_pa(pa1);
  int woken = 0, requeued = 0;

  // Phase 1: wake up to 'count' waiters from b1.
  acquire(&b1->lock);
  struct futex_waiter **pp = &b1->waiters;
  while(*pp && woken < count) {
    struct futex_waiter *w = *pp;
    if(w->pa == pa1) {
      *pp = w->next;
      woken++;
      release(&b1->lock);
      futex_wakeup_proc(w->proc);
      acquire(&b1->lock);
    } else {
      pp = &(*pp)->next;
    }
  }

  // Phase 2: requeue remaining waiters from b1 to b2.
  // Release b1->lock before acquiring b2->lock to avoid deadlock
  // with futex_wait on b2.
  release(&b1->lock);

  if(count2 > 0) {
    struct futex_bucket *b2 = futex_bucket_from_pa(pa2);
    acquire(&b2->lock);
    acquire(&b1->lock);
    pp = &b1->waiters;
    while(*pp && requeued < count2) {
      struct futex_waiter *w = *pp;
      if(w->pa == pa1) {
        *pp = w->next;
        w->pa = pa2;
        w->next = b2->waiters;
        b2->waiters = w;
        requeued++;
      } else {
        pp = &(*pp)->next;
      }
    }
    release(&b1->lock);
    release(&b2->lock);
  }

  return woken + requeued;
}

