// clone3 syscall (Linux 5.10, nr=435).
// struct clone_args is defined in include/uapi/linux/sched.h.
// We support the subset of fields needed for glibc 2.39 pthread_create.
struct clone_args {
  uint64 flags;
  uint64 pidfd;         // ignored (no pidfd support)
  uint64 child_tid;
  uint64 parent_tid;
  uint64 exit_signal;
  uint64 stack;
  uint64 stack_size;    // ignored
  uint64 tls;
  uint64 set_tid;       // ignored
  uint64 set_tid_size;  // ignored
  uint64 cgroup;        // ignored
};

uint64
sys_clone3(void)
{
  uint64 uaddr, usize;
  struct clone_args args;

  argaddr(0, &uaddr);
  argaddr(1, &usize);

  // Validate size: must be > 0 and <= sizeof(struct clone_args)
  if (usize == 0 || usize > sizeof(struct clone_args))
    return -EINVAL;

  // Copy struct from userspace
  if (copyin(myproc()->mm->pagetable, (char*)&args, uaddr, usize) < 0)
    return -EFAULT;

  // Zero-fill fields not provided by userspace (if usize < sizeof(args))
  if (usize < sizeof(struct clone_args))
    memset((char*)&args + usize, 0, sizeof(struct clone_args) - usize);

  // Merge exit_signal into flags (lower byte = CSIGNAL mask)
  uint64 flags = args.flags | (args.exit_signal & CSIGNAL);

  // glibc passes child_tid in the struct but may not set CLONE_CHILD_CLEARTID
  // in flags. Infer CLEARTID/SETTID when the pointers are provided.
  // IMPORTANT: only infer CLEARTID for threads (CLONE_VM), not for processes.
  // For process fork, CLEARTID would cause futex_wake to fire when the child
  // exits, waking the parent prematurely and reaping the zombie before the
  // parent can observe it (e.g. "kill $!" fails with ESRCH).
  if (args.child_tid && (flags & CLONE_VM) && !(flags & CLONE_CHILD_CLEARTID))
    flags |= CLONE_CHILD_CLEARTID;
  if (args.parent_tid && !(flags & CLONE_PARENT_SETTID))
    flags |= CLONE_PARENT_SETTID;

  if (flags & CLONE_VM) {
    // Linux clone3 ABI: args.stack is the LOWEST address of the stack.
    // The child's initial SP must be stack + stack_size (the TOP).
    uint64 child_sp = args.stack + args.stack_size;
    return kclone(flags, child_sp, args.parent_tid, args.tls, args.child_tid);
  } else {
    return kfork(flags, args.child_tid);
  }
}

