// Linux brk 语义：addr 是绝对地址，addr=0 查询当前 brk
// Phase 4: 操作 heap VMA 而非直接设置 mm->brk
uint64
sys_brk(void)
{
  uint64 addr;
  argaddr(0, &addr);

  struct proc *p = myproc();
  uint64 oldbrk = p->mm->brk;

  // addr == 0：查询当前 brk
  if(addr == 0)
    return oldbrk;

  // 页对齐
  addr = PGROUNDUP(addr);

  if(addr == oldbrk)
    return addr;

  // 不允许缩小到 start_brk 以下
  if(addr < p->mm->start_brk)
    return oldbrk;

  // 查找并操作 heap VMA（持 mmap_lock 保护 VMA 元数据一致性）
  acquiresleep(&p->mm->mmap_lock);
  struct vma *heap_vma = vma_find_by_start(p->mm, p->mm->start_brk);

  if(heap_vma == 0){
    // heap VMA 应始终存在（exec 创建），缺失则返回旧 brk
    releasesleep(&p->mm->mmap_lock);
    return oldbrk;
  }

  if(addr > oldbrk){
    // Eagerly allocate physical pages (SC7 approach: growproc→uvmalloc).
    // Lazy allocation via page faults can corrupt glibc's heap metadata
    // if the fault handler maps pages with wrong permissions or bounds.
    uint64 pg_old = PGROUNDUP(oldbrk);
    uint64 pg_new = PGROUNDUP(addr);
    if (pg_new > pg_old) {
      acquire(&p->mm->page_table_lock);
      if (uvmalloc(p->mm->pagetable, pg_old, pg_new, PTE_R|PTE_W) == 0) {
        release(&p->mm->page_table_lock);
        releasesleep(&p->mm->mmap_lock);
        return oldbrk;
      }
      release(&p->mm->page_table_lock);
    }
    // 扩展 heap VMA
    heap_vma->end = addr;
    p->mm->brk = addr;
  } else if(addr < oldbrk){
    // 缩小 heap VMA：释放多余页面
    uint64 oldend = PGROUNDUP(oldbrk);
    uint64 newend = PGROUNDUP(addr);
    if(newend < oldend){
      acquire(&p->mm->page_table_lock);
      uvmunmap(p->mm->pagetable, newend, (oldend - newend) / PGSIZE, 1);
      sfence_vma();
      release(&p->mm->page_table_lock);
    }
    heap_vma->end = addr;
    p->mm->brk = addr;
  }
  releasesleep(&p->mm->mmap_lock);

  //printf("brk: old=0x%lx new=0x%lx pid=%d name=%s\n", oldbrk, addr, p->pid, p->name);
  return addr;
}

uint64
sys_pause(void)
{
  int n;
  uint ticks0;

  argint(0, &n);
  if(n < 0)
    n = 0;
  acquire(&tickslock);
  ticks0 = ticks;
  while(ticks - ticks0 < n){
    if(killed(myproc())){
      release(&tickslock);
      return -EINTR;
    }
    sleep(&ticks, &tickslock);
  }
  release(&tickslock);
  return 0;
}

