/* Static socket table */
static socket_t socket_table[MAX_SOCKETS];
static struct spinlock socket_lock;
static int socket_initialized = 0;

/* Ephemeral port allocator (a20-style: pre-allocate before lwIP) */
static uint16 next_ephemeral = 49152;

static uint16 alloc_ephemeral_port(void)
{
  uint16 p = next_ephemeral++;
  if (next_ephemeral < 49152)
    next_ephemeral = 49152;
  return p;
}

/*
 * Convert sockaddr_in to lwIP ip_addr_t + port.
 * Returns 0 on success, -1 on error.
 */
static int
sockaddr_to_lwip(const struct sockaddr_in *sin, ip_addr_t *ipaddr, uint16 *port)
{
  if (sin->sin_family != AF_INET)
    return -1;
  ip4_addr_set_u32(ipaddr, sin->sin_addr);
  *port = ntohs(sin->sin_port);  /* Convert from network to host byte order */
  return 0;
}

/*
 * Convert lwIP ip_addr_t + port to sockaddr_in.
 */
static void
lwip_to_sockaddr(struct sockaddr_in *sin, const ip_addr_t *ipaddr, uint16 port)
{
  sin->sin_family = AF_INET;
  sin->sin_port = htons(port);  /* Convert from host to network byte order */
  sin->sin_addr = ip4_addr_get_u32(ipaddr);
  memset(sin->sin_zero, 0, sizeof(sin->sin_zero));
}

/*
 * TCP receive callback. Called by lwIP when data arrives on a TCP connection.
 * Appends received pbuf to the socket's recv buffer.
 */
static err_t
tcp_recv_cb(void *arg, struct tcp_pcb *tpcb, struct pbuf *p, err_t err)
{
  socket_t *sock = (socket_t *)arg;

  if (p == NULL) {
    /* Connection closed by remote */
    sock->state = SOCKET_CLOSING;
    return ERR_OK;
  }

  if (err != ERR_OK) {
    pbuf_free(p);
    sock->err = err;
    return err;
  }

  /* Append to receive buffer */
  if (sock->recv_buf == NULL) {
    sock->recv_buf = p;
  } else {
    pbuf_chain(sock->recv_buf, p);
  }
  sock->recv_buf_len += p->tot_len;

  /* Wake up any process sleeping in recvfrom or pselect6 */
  wakeup(&sock->recv_buf);

  /* Acknowledge received data */
  tcp_recved(tpcb, p->tot_len);

  return ERR_OK;
}

/*
 * TCP connected callback. Called when an outgoing connection completes.
 */
static err_t
tcp_connected_cb(void *arg, struct tcp_pcb *tpcb, err_t err)
{
  socket_t *sock = (socket_t *)arg;

  if (err == ERR_OK) {
    sock->state = SOCKET_CONNECTED;
  } else {
    sock->err = err;
  }

  return ERR_OK;
}

/*
 * TCP error callback. Called when a fatal error occurs on a PCB.
 * NOTE: the PCB is already freed when this callback is called.
 */
static void
tcp_err_cb(void *arg, err_t err)
{
  socket_t *sock = (socket_t *)arg;

  sock->tcp_pcb = NULL;
  sock->err = err;
  if (sock->state != SOCKET_FREE && sock->state != SOCKET_CLOSED)
    sock->state = SOCKET_CLOSED;
}

/*
 * TCP accept callback. Called when a new connection arrives on a listening PCB.
 * Stores the new PCB in the socket's tcp_pcb field for socket_accept() to pick up.
 */
static err_t
tcp_accept_cb(void *arg, struct tcp_pcb *newpcb, err_t err)
{
  socket_t *sock = (socket_t *)arg;

  if (err != ERR_OK || newpcb == NULL)
    return ERR_VAL;

  /* If there's already a pending accept, reject this one */
  if (sock->tcp_pcb != NULL) {
    tcp_abort(newpcb);
    return ERR_ABRT;
  }

  /* Set up callbacks on the new PCB */
  sock->tcp_pcb = newpcb;
  tcp_arg(newpcb, sock);
  tcp_recv(newpcb, tcp_recv_cb);
  tcp_err(newpcb, tcp_err_cb);

  /* Record remote address */
  lwip_to_sockaddr(&sock->remote_addr, &newpcb->remote_ip, newpcb->remote_port);

  sock->state = SOCKET_CONNECTED;
  wakeup(sock);  // wake accept() sleeping on sock

  return ERR_OK;
}

/*
 * UDP receive callback. Called by lwIP when a UDP datagram arrives.
 */
static void
udp_recv_cb(void *arg, struct udp_pcb *pcb, struct pbuf *p,
            const ip_addr_t *addr, u16_t port)
{
  socket_t *sock = (socket_t *)arg;

  if (p == NULL)
    return;

  /* Append to receive buffer */
  if (sock->recv_buf == NULL) {
    sock->recv_buf = p;
  } else {
    pbuf_chain(sock->recv_buf, p);
  }
  sock->recv_buf_len += p->tot_len;
  /* Wake up any process sleeping in recvfrom or pselect6 */
  wakeup(&sock->recv_buf);
}

/*
 * Initialize the socket subsystem.
 */
void
socket_init(void)
{
  int i;

  if (socket_initialized)
    return;

  initlock(&socket_lock, "socket");
  for (i = 0; i < MAX_SOCKETS; i++) {
    socket_table[i].used = 0;
    socket_table[i].state = SOCKET_FREE;
  }
  socket_initialized = 1;
}

/*
 * Allocate and initialize a new socket.
 * Returns a real file descriptor from the process fd table, or negative errno.
 */
int
socket_create(int domain, int type, int protocol)
{
  socket_t *sock;
  int i;
  struct proc *p = myproc();
  struct file *f;
  int fd;

  if (domain != AF_INET)
    return -EAFNOSUPPORT;

  /* Mask off flags that are OR'd with type (SOCK_CLOEXEC=0x80000, SOCK_NONBLOCK=0x800) */
  int sock_flags = type & ~0xf;  /* Extract SOCK_CLOEXEC, SOCK_NONBLOCK etc. */
  int sock_type = type & 0xf;    /* Linux SOCK_TYPE_MASK */
  if (sock_type != SOCK_STREAM && sock_type != SOCK_DGRAM)
    return -ESOCKTNOSUPPORT;

  /* Allocate a file structure */
  f = filealloc();
  if (f == 0)
    return -EMFILE;

  /* Allocate a file descriptor from the process */
  for (fd = 0; fd < NOFILE; fd++) {
    if (p->ft->ofile[fd] == 0)
      break;
  }
  if (fd >= NOFILE) {
    filefree(f);
    return -EMFILE;
  }

  /* Find a free socket slot */
  acquire(&socket_lock);
  for (i = 0; i < MAX_SOCKETS; i++) {
    if (!socket_table[i].used)
      break;
  }
  if (i >= MAX_SOCKETS) {
    release(&socket_lock);
    filefree(f);
    return -ENFILE;
  }

  sock = &socket_table[i];
  memset(sock, 0, sizeof(socket_t));
  sock->used = 1;
  sock->domain = domain;
  sock->type = sock_type;  /* Store masked type (without SOCK_CLOEXEC etc.) */
  sock->protocol = protocol;
  sock->state = SOCKET_CREATED;
  sock->nonblocking = (sock_flags & SOCK_NONBLOCK) ? 1 : 0;
  /* Initialize local_addr to a valid empty address so getsockname
   * returns a consistent value even before bind() is called. */
  sock->local_addr.sin_family = AF_INET;
  sock->local_addr.sin_port = 0;
  sock->local_addr.sin_addr = 0;
  memset(sock->local_addr.sin_zero, 0, sizeof(sock->local_addr.sin_zero));

  /* Create the appropriate lwIP PCB */
  lwip_op_begin();
  if (sock_type == SOCK_STREAM) {
    sock->tcp_pcb = tcp_new();
    if (sock->tcp_pcb == NULL) {
      sock->used = 0;
      release(&socket_lock);
      filefree(f);
      lwip_op_end();
      return -ENOMEM;
    }
    tcp_arg(sock->tcp_pcb, sock);
    tcp_recv(sock->tcp_pcb, tcp_recv_cb);
    tcp_err(sock->tcp_pcb, tcp_err_cb);
  } else if (sock_type == SOCK_DGRAM) {
    sock->udp_pcb = udp_new();
    if (sock->udp_pcb == NULL) {
      sock->used = 0;
      release(&socket_lock);
      filefree(f);
      lwip_op_end();
      return -ENOMEM;
    }
    udp_recv(sock->udp_pcb, udp_recv_cb, sock);
  }
  lwip_op_end();

  release(&socket_lock);

  /* Set up file structure */
  f->type = FD_SOCKET;
  f->readable = 1;
  f->writable = 1;
  f->socket = sock;
  f->ref = 1;
  f->flags = 0;  /* Blocking mode by default */

  /* Register in process fd table */
  p->ft->ofile[fd] = f;

  return fd;
}

/*
 * Look up a socket by file descriptor.
 * Returns a pointer to the socket, or NULL if not found.
 */
socket_t *
socket_get(int fd)
{
  struct proc *p = myproc();
  struct file *f;

  if (fd < 0 || fd >= NOFILE)
    return NULL;

  f = p->ft->ofile[fd];
  if (f == NULL || f->type != FD_SOCKET)
    return NULL;

  return (socket_t *)f->socket;
}

