shm_alloc_slot(void)
{
    for (int i = 0; i < MAX_SHM_SEGS; i++) {
        if (!shm_segs[i].used)
            return &shm_segs[i];
    }
    return 0;
}

// Free all physical resources of a segment (pages + page array).
// Caller must hold shm_lock.
static void
shm_free_resources(struct shm_seg *seg)
{
    if (seg->pages) {
        for (int i = 0; i < seg->npages; i++) {
            if (seg->pages[i])
                kfree_page((void *)seg->pages[i]);
        }
        kfree(seg->pages);
        seg->pages = 0;
    }
    seg->used = 0;
}

// --------------- VMA close callback ---------------

// Called when a shm VMA is fully removed (vma_remove CASE1 or vma_free_all).
// Decrements nattch and frees segment resources if last attach + marked for delete.
static void
shm_close(struct vma *v)
{
    struct shm_seg *seg = (struct shm_seg *)v->vm_private_data;
    if (seg == 0)
        return;

    acquire(&shm_lock);
    if (seg->nattch > 0)
        seg->nattch--;
    // Auto-free when last process detaches. POSIX would keep the segment
    // alive for later re-attach by key, but our embedded use case (iozone)
    // creates IPC_PRIVATE segments that are single-use.  Without this,
    // segments leak and the 16-slot table fills up after a few subtests.
    if (seg->nattch == 0)
        shm_free_resources(seg);
    release(&shm_lock);
}

struct vm_operations shm_vm_ops = {
    .fault = 0,    // not needed — pages are pre-mapped
    .close = shm_close,
};

// --------------- fork helper ---------------

// Called from kfork for each shm VMA: share physical pages (no copy).
// Maps parent's physical pages directly into child's page table.
int
shm_fork_share(struct vma *vma, pagetable_t parent_pt, pagetable_t child_pt)
{
    struct shm_seg *seg = (struct shm_seg *)vma->vm_private_data;
    if (seg == 0)
        return -1;

    pte_t *pte;
    for (uint64 va = vma->start; va < vma->end; va += PGSIZE) {
        pte = walk(parent_pt, va, 0);
        if (pte == 0 || (*pte & PTE_V) == 0)
            continue;
        // If already mapped in child, unmap first (don't free — it's a
        // stale copy from the adjacent anonymous VMA's uvmcopy_range).
        if (walkaddr(child_pt, va) != 0)
            uvmunmap(child_pt, va, 1, 1);  // free the stale copy
        uint64 pa = PTE2PA(*pte);
        int flags = PTE_FLAGS(*pte);
        if (mappages(child_pt, va, PGSIZE, pa, flags) < 0)
            return -1;
    }

    acquire(&shm_lock);
    seg->nattch++;
    release(&shm_lock);
    return 0;
}

// --------------- syscall implementations ---------------

// shmget(194): get or create a System V shared memory segment
//   key: IPC_PRIVATE (0) to create new, or user-specified key
//   size: segment size in bytes (page-aligned internally)
//   shmflg: IPC_CREAT | IPC_EXCL | permission bits
// Returns: shmid (>= 0) on success, negative errno on failure
uint64
sys_shmget(void)
{
    int key, size, shmflg;

    argint(0, &key);
    argint(1, &size);
    argint(2, &shmflg);

    if (size < 0)
        return -EINVAL;

    // Cap at 256MB to prevent excessive allocation
    if (size > 256 * 1024 * 1024)
        return -EINVAL;

    acquire(&shm_lock);

    // IPC_PRIVATE (key == 0): always create a new segment
    if (key != IPC_PRIVATE) {
        struct shm_seg *existing = shm_find_by_key((uint)key);
        if (existing) {
            // Found existing segment
            if ((shmflg & (IPC_CREAT | IPC_EXCL)) == (IPC_CREAT | IPC_EXCL)) {
                release(&shm_lock);
                return -EEXIST;
            }
            if ((uint64)size > existing->size) {
                release(&shm_lock);
                return -EINVAL;
            }
            // Simple permission check: allow if creator or mode allows
            release(&shm_lock);
            return existing->id;
        }
        // Not found — need IPC_CREAT to create
        if (!(shmflg & IPC_CREAT)) {
            release(&shm_lock);
            return -ENOENT;
        }
    }

    // Create new segment
    struct shm_seg *seg = shm_alloc_slot();
    if (seg == 0) {
        release(&shm_lock);
        return -ENOSPC;
    }

    // Minimum 1 page
    if (size <= 0)
        size = PGSIZE;

    int npages = PGROUNDUP((uint64)size) / PGSIZE;

    // Allocate page pointer array
    seg->pages = (uint64 *)kmalloc(npages * sizeof(uint64));
    if (seg->pages == 0) {
        release(&shm_lock);
        return -ENOMEM;
    }
    memset(seg->pages, 0, npages * sizeof(uint64));

    // Allocate physical pages
    int alloc_ok = 1;
    for (int i = 0; i < npages; i++) {
        seg->pages[i] = (uint64)kalloc();
        if (seg->pages[i] == 0) {
            alloc_ok = 0;
            break;
        }
        memset((void *)seg->pages[i], 0, PGSIZE);
    }

    if (!alloc_ok) {
        for (int i = 0; i < npages; i++) {
            if (seg->pages[i])
                kfree_page((void *)seg->pages[i]);
        }
        kfree(seg->pages);
        seg->pages = 0;
        release(&shm_lock);
        return -ENOMEM;
    }

    seg->used = 1;
    seg->id = shm_next_id++;
    seg->key = (uint)key;
    seg->size = (uint64)size;
    seg->npages = npages;
    seg->nattch = 0;
    seg->mode = (uint64)(shmflg & 0777);
    seg->mark_delete = 0;
    seg->cpid = myproc()->pid;
    seg->lpid = 0;
    seg->atime = 0;
    seg->dtime = 0;
    seg->ctime = 0;

    release(&shm_lock);
    return seg->id;
}

