// System V shared memory subsystem
// Implements: shmget(194), shmat(196), shmdt(197), shmctl(195)

#ifndef _KERNEL_SHM_H
#define _KERNEL_SHM_H

#include "types.h"

#define MAX_SHM_SEGS    16

// IPC flags (same as Linux asm-generic/ipc.h)
#define IPC_PRIVATE     0
#define IPC_CREAT       00001000
#define IPC_EXCL        00002000

// shmctl commands
#define IPC_RMID        0
#define IPC_SET         1
#define IPC_STAT        2

// shmat flags
#define SHM_RDONLY      0x1000
#define SHM_RND         0x2000
#define SHM_REMAP       0x4000
#define SHM_EXEC        0x100000

// shmid_ds: returned to userspace for IPC_STAT
struct shmid_ds {
    uint64 shm_segsz;      // segment size
    uint64 shm_atime;      // last attach time
    uint64 shm_dtime;      // last detach time
    uint64 shm_ctime;      // last change time
    uint   shm_cpid;       // creator pid
    uint   shm_lpid;       // last operation pid
    uint   shm_nattch;     // current attach count
    uint   shm_perm_mode;  // permissions
    uint64 __unused[2];
};

// Internal shared memory segment descriptor
struct shm_seg {
    int used;              // 1 if slot is in use
    int id;                // shmid (returned to userspace)
    uint key;              // IPC key (0 = IPC_PRIVATE)
    uint64 size;           // requested size in bytes
    int npages;            // number of allocated 4KB pages
    uint64 *pages;         // kmalloc'd array of physical page addresses
    int nattch;            // number of current attaches
    uint64 mode;           // permissions (e.g., 0600)
    int mark_delete;       // IPC_RMID called but still attached
    uint cpid;             // creator pid
    uint lpid;             // last operation pid
    uint64 atime;          // last attach time
    uint64 dtime;          // last detach time
    uint64 ctime;          // last change time
};

// Global state
extern struct shm_seg shm_segs[MAX_SHM_SEGS];
extern struct spinlock shm_lock;

// shm_vm_ops for VMA integration
extern struct vm_operations shm_vm_ops;

#endif // _KERNEL_SHM_H

