// xv6 文件映射 fault handler
static uint64 xv6_file_fault(struct vma *v, uint64 addr, int write) {
  uint64 mem = (uint64)kalloc();
  if(mem == 0) return 0;
  memset((void *)mem, 0, PGSIZE);
  uint64 file_off = v->file_offset + (addr - v->start);
  uint64 n = v->end - addr;
  if(n > PGSIZE) n = PGSIZE;
  ilock(v->file->ip);
  xv6_readi(XV6_INODE(v->file->ip), 0, mem, file_off, n);
  iunlock(v->file->ip);
  return vma_map_page(myproc()->mm, v, addr, mem);
}

