// 分配一个vfs superblock，返回一个xv6 inode
static struct inode *xv6_alloc_inode(struct super_block *sb){
  struct xv6_inode_info *xii = kmem_cache_alloc(xv6_inode_cachep);  // 分配内存
  if (!xii) return 0;
  memset(xii, 0, sizeof(*xii));             // 置0
  xii->vfs_inode.i_op = &xv6_inode_ops;     // 设置inode操作
  xii->vfs_inode.i_fop = &xv6_file_ops;     // 设置file操作
  xii->vfs_inode.i_sb = sb;                 // 设置super block
  return &xii->vfs_inode;
}

// 释放一个vfs superblock，释放一个xv6 inode
static void xv6_destroy_inode(struct super_block *sb, struct inode *ip){
  struct xv6_inode_info *xii = XV6_INODE(ip);   // 从inode得到xv6_inode_info
  kmem_cache_free(xv6_inode_cachep, xii);       // 释放内存
}

// 从磁盘清除inode，调用者必须持有ip->lock，内部处理日志
void xv6_evict_inode(struct inode *ip){
  struct xv6_inode_info *xii = XV6_INODE(ip);
  xv6_begin_op();
  xv6_itrunc(xii);
  xii->vfs_inode.type = 0;
  xv6_iupdate(xii);
  xii->vfs_inode.valid = 0;
  xv6_end_op();
}

// 从磁盘读出inode的数据，填入ip
// ip中已有dev, inum, sb
void xv6_read_inode(struct inode *ip){
  struct xv6_inode_info *xii = XV6_INODE(ip);
  struct xv6_sb_info *sbi = (struct xv6_sb_info *)ip->i_sb->s_fs_info;
  struct xv6_sb_info sb = *sbi;
  struct buf *bp = bread(ip->dev, IBLOCK(ip->inum, sb));
  struct xv6_dinode *dip = (struct xv6_dinode *)bp->data + ip->inum%IPB;
  ip->type = dip->type;
  ip->major = dip->major;
  ip->minor = dip->minor;
  ip->nlink = dip->nlink;
  ip->size = dip->size;
  memmove(xii->addrs, dip->addrs, sizeof(xii->addrs));
  brelse(bp);
}

// 释放superblock
void xv6_put_super(struct super_block *sb){
  struct xv6_sb_info *xv6_sb = (struct xv6_sb_info *)sb->s_fs_info;
  kfree_page(xv6_sb);
  // kfree_page(sb); umount负责free sb
}

