// 在dir下查找name文件，返回其inode，flags用于权限检查
// 返回的inode不带锁
static struct inode *xv6_lookup(struct inode *dir, const char *name){
  return xv6_dirlookup(XV6_INODE(dir), name, 0);
}

// 创建普通文件，不检查是否已经存在
// 返回的inode不带锁
static struct inode *xv6_create(struct inode *dir, const char *name, uint16 mode){
  xv6_begin_op();
  ilock(dir);
  struct inode *ip = xv6_ialloc(dir->i_sb, T_FILE);
  if(ip == 0){
    iunlock(dir);
    xv6_end_op();
    return 0;
  }

  ilock(ip);

  if(xv6_dirlink(XV6_INODE(dir), name, ip->inum) == 0){
    ip->nlink = 1;
    xv6_iupdate(XV6_INODE(ip));
    // caller expects ip locked, dir locked kept for caller
    iunlock(dir);
    xv6_end_op();
    return ip;
  }
  iunlockput(ip);
  iunlock(dir);
  xv6_end_op();
  return 0;
}

