static struct inode *
lwext4_alloc_inode(struct super_block *sb)
{
    struct lwext4_inode_info *lii = kmem_cache_alloc(lwext4_inode_cachep);
    if (!lii) return 0;
    memset(lii, 0, sizeof(*lii));
    lii->vfs_inode.i_op = &lwext4_inode_ops;
    lii->vfs_inode.i_fop = &lwext4_file_ops;
    lii->vfs_inode.i_sb = sb;
    return &lii->vfs_inode;
}

static void
lwext4_destroy_inode(struct super_block *sb, struct inode *ip)
{
    (void)sb;
    struct lwext4_inode_info *lii = LWEXT4_IIP(ip);
    kmem_cache_free(lwext4_inode_cachep, lii);
}

static void
lwext4_read_inode(struct inode *ip)
{
    struct lwext4_inode_info *lii = LWEXT4_IIP(ip);
    struct ext4_inode raw;
    uint32 ino = 0;

    int rc = ext4_raw_inode_fill(lii->path, &ino, &raw);
    if (rc != EOK) {
        printf("lwext4_read_inode: failed for %s (rc=%d)\n", lii->path, rc);
        return;
    }

    struct ext4_sblock *sb = 0;
    ext4_get_sblock(lii->path, &sb);
    if (!sb) {
        printf("lwext4_read_inode: no sblock for %s\n", lii->path);
        return;
    }

    uint16 mode = ext4_inode_get_mode(sb, &raw);

    if ((mode & S_IFMT) == S_IFDIR)
        ip->type = T_DIR;
    else if ((mode & S_IFMT) == S_IFREG)
        ip->type = T_FILE;
    else if ((mode & S_IFMT) == S_IFCHR)
        ip->type = T_DEVICE;
    else if ((mode & S_IFMT) == S_IFBLK)
        ip->type = T_DEVICE;
    else if ((mode & S_IFMT) == S_IFLNK)
        ip->type = T_SYMLINK;
    else
        ip->type = T_FILE;  // default to regular file

    ip->nlink = ext4_inode_get_links_cnt(&raw);
    ip->size = ext4_inode_get_size(sb, &raw);
    ip->valid = 1;
}

static void
lwext4_evict_inode(struct inode *ip)
{
    ip->valid = 0;
}

