// ==================== inode_operations ====================

static struct inode *
lwext4_lookup(struct inode *dir, const char *name)
{
    struct lwext4_inode_info *dir_info = LWEXT4_IIP(dir);

    // Build child path: dir_path + "/" + name
    char child_path[MAXPATH];
    int dir_len = strlen(dir_info->path);

    // Handle root directory (path is "/")
    if (dir_len == 1 && dir_info->path[0] == '/') {
        snprintf(child_path, MAXPATH, "/%s", name);
    } else {
        snprintf(child_path, MAXPATH, "%s/%s", dir_info->path, name);
    }

    // Verify path exists via lwext4
    struct ext4_inode raw;
    uint32 ino = 0;
    int rc = ext4_raw_inode_fill(child_path, &ino, &raw);
    if (rc != EOK)
        return 0;  // not found

    // Get VFS inode (may be cached)
    struct inode *ip = iget(dir->dev, ino, dir->i_sb);
    if (ip) {
        // Only set path on newly-created inodes (empty path).
        // If the inode is already cached (e.g. "." or ".." returning the
        // same inode as the parent), its path is already correct and must
        // NOT be overwritten -- otherwise the path accumulates "/../."
        // garbage from repeated self-referencing lookups.
        struct lwext4_inode_info *child_info = LWEXT4_IIP(ip);
        if (child_info->path[0] == '\0') {
            safestrcpy(child_info->path, child_path, MAXPATH);
        }
    }
    return ip;
}

static struct inode *
lwext4_create(struct inode *dir, const char *name, uint16 mode)
{
    struct lwext4_inode_info *dir_info = LWEXT4_IIP(dir);
    char child_path[MAXPATH];
    int dir_len = strlen(dir_info->path);

    if (dir_len == 1 && dir_info->path[0] == '/')
        snprintf(child_path, MAXPATH, "/%s", name);
    else
        snprintf(child_path, MAXPATH, "%s/%s", dir_info->path, name);

    (void)mode;
    // Create file using lwext4
    ext4_file f;

