// Fetch the nth word-sized system call argument as a file descriptor
// and return both the descriptor and the corresponding struct file.
static int
argfd(int n, int *pfd, struct file **pf)
{
  int fd;
  struct file *f;

  argint(n, &fd);
  if(fd < 0 || fd >= NOFILE || (f=myproc()->ft->ofile[fd]) == 0)
    return -EBADF;
  if(pfd)
    *pfd = fd;
  if(pf)
    *pf = f;
  return 0;
}

// Allocate a file descriptor for the given file.
static int
fdalloc(struct file *f)
{
  int fd;
  struct proc *p = myproc();
  int limit = NOFILE;
  uint64 nofile_limit = p->rlimits[7].cur;  // RLIMIT_NOFILE = 7
  if(nofile_limit > 0 && nofile_limit < NOFILE)
    limit = (int)nofile_limit;

  for(fd = 0; fd < limit; fd++){
    if(p->ft->ofile[fd] == 0){
      p->ft->ofile[fd] = f;
      return fd;
    }
  }
  return -EMFILE;
}

uint64
sys_dup(void)
{
  struct file *f;
  int fd;

  if(argfd(0, 0, &f) < 0)
    return -EBADF;
  if((fd=fdalloc(f)) < 0)
    return -EMFILE;
  filedup(f);
  return fd;
}

// sys_dup3，但传入的flags固定为0
// 若newfd在调用前已经是被打开的文件描述符会原子性的关闭旧的newfd并将oldfd复制过去
// newfd=oldfd时报错
uint64 sys_dup3(void){
  struct file *oldf;
  int new_fd;
  int old_fd;
  int flags;

  // 获取参数
  if(argfd(0, &old_fd, &oldf) < 0){
    return -EBADF;
  }
  argint(1, &new_fd);
  argint(2, &flags);

  if(old_fd == new_fd){
    return -EINVAL;
  }

  struct proc *p = myproc();
  if(new_fd < 0 || new_fd >= NOFILE){
    return -EBADF;
  }

  // xv6进入syscall时持有p->lock，单核调度，所以关和再分配是原子的
  if(p->ft->ofile[new_fd]){
    fileclose(p->ft->ofile[new_fd]);
  }
  p->ft->ofile[new_fd] = filedup(oldf);
  return new_fd;
}

// fcntl - file control
// Linux fcntl commands
#define F_DUPFD         0
#define F_GETFD         1
#define F_SETFD         2
#define F_GETFL         3
#define F_SETFL         4
#define F_DUPFD_CLOEXEC 1030

uint64
sys_fcntl(void)
{
  struct file *f;
  int fd, cmd, arg;

  if(argfd(0, &fd, &f) < 0)
    return -EBADF;
  argint(1, &cmd);
  argint(2, &arg);

  switch(cmd){
  case F_DUPFD:
  case F_DUPFD_CLOEXEC:{
    // Duplicate fd to the lowest numbered available fd >= arg
    int newfd;
    if(arg < 0 || arg >= NOFILE)
      return -EINVAL;
    struct proc *p = myproc();
    for(newfd = arg; newfd < NOFILE; newfd++){
      if(p->ft->ofile[newfd] == 0){
        p->ft->ofile[newfd] = f;
        filedup(f);
        // NOTE: F_DUPFD_CLOEXEC should set close-on-exec on the NEW fd only.
        // Since xv6 stores FD_CLOEXEC on the shared struct file (not per-fd),
        // setting it here would corrupt the original fd too. Skip for now.
        // The fd table entry above is the only change we make.
        return newfd;
      }
    }
    return -EMFILE;
  }
  case F_GETFD:
    return (f->flags & FD_CLOEXEC) ? FD_CLOEXEC : 0;
  case F_SETFD:
    if(arg & FD_CLOEXEC)
      f->flags |= FD_CLOEXEC;
    else
      f->flags &= ~FD_CLOEXEC;
    return 0;
  case F_GETFL: {
    int fl = 0;
    if(f->readable && f->writable)
      fl = O_RDWR;
    else if(f->writable)
      fl = O_WRONLY;
    else
      fl = O_RDONLY;
    return fl;
  }
  case F_SETFL:
    return 0;  // Ignore
  default:
    return -EINVAL;
  }
}

static struct file* recover_stdio(int fd);

uint64
sys_read(void)
{
  struct file *f;
  int n;
  uint64 p;
  int fd;

  argint(0, &fd);
  argaddr(1, &p);
  argint(2, &n);
  if(argfd(0, 0, &f) < 0){
    if(fd >= 0 && fd <= 2)
      f = recover_stdio(fd);
    if(f == 0)
      return -EBADF;
  }
  int ret = fileread(f, p, n);
  if(ret == -EBADF && fd >= 0 && fd <= 2){
    f = recover_stdio(fd);
    if(f)
      ret = fileread(f, p, n);
  }
  return ret;
}

