// =========================
// VMA 链表操作（调用者持 mmap_lock）
// 链表按 end 降序：链表头 end 最大（最接近 MMAP_BASE）
// =========================

struct vma *
vma_find(struct mm_struct *mm, uint64 va)
{
    struct vma *v;
    list_for_each_entry(v, &mm->mmap_list, node) {
        if (va >= v->start && va < v->end)
            return v;
    }
    return 0;
}

// 按 start 地址精确查找 VMA（用于查找 start==end 的零长 VMA）
// 调用者需持 mm->mmap_lock
struct vma *
vma_find_by_start(struct mm_struct *mm, uint64 start)
{
    struct vma *v;
    list_for_each_entry(v, &mm->mmap_list, node) {
        if (v->start == start)
            return v;
    }
    return 0;
}

// 从 MMAP_BASE 向下搜索长度为 length 的空闲地址区间
// 链表按 end 降序，遍历方向 = mmap 增长方向
uint64
vma_find_free_area(struct mm_struct *mm, uint64 length)
{
    uint64 gap_high = MMAP_BASE;

    struct vma *v;
    list_for_each_entry(v, &mm->mmap_list, node) {
        // 间隙 [v->end, gap_high)
        // skip zero-length VMAs (initial brk placeholder)
        if (v->start == v->end)
            continue;
        if (gap_high >= v->end && gap_high - v->end >= length)
            return gap_high - length;
        gap_high = v->start;
    }
    // Also check gap between lowest VMA and address 0
    if (gap_high >= length)
        return gap_high - length;
    return 0;
}

// 按 end 降序插入
void
vma_insert(struct mm_struct *mm, struct vma *v)
{
    struct vma *pos;
    list_for_each_entry(pos, &mm->mmap_list, node) {
        if (pos->end <= v->end)
            break;
    }
    list_add_tail(&v->node, &pos->node);
}

struct vma *
vma_create(struct mm_struct *mm, uint64 start, uint64 len,
           uint64 vm_flags, struct file *file, uint64 file_offset)
{
    // start == ~0UL means "auto-allocate" (used by mmap).
    // start == 0 means explicitly map at VA=0 (page 0 guard page).
    if (start == ~0UL) {
        start = vma_find_free_area(mm, len);
        if (start == 0)
            return 0;
    }

    if (vma_find(mm, start))
        return 0;

    struct vma *v = kmem_cache_alloc(vma_cachep);
    if (v == 0)
        return 0;

    LIST_HEAD_INIT(v->node);
    v->start = start;
    v->end = start + len;
    v->vm_flags = vm_flags;
    v->file = file;
    v->file_offset = file_offset;
    v->vm_ops = 0;
    v->vm_private_data = 0;

    vma_insert(mm, v);
    return v;
}

int
vma_remove(struct mm_struct *mm, uint64 start, uint64 len)
{
    uint64 end = start + len;
    struct vma *v, *n;

    // 链表按 end 降序，正向遍历（从高地址到低地址）
    list_for_each_entry_safe(v, n, &mm->mmap_list, node) {
        // 没有重叠：VMA 完全在目标范围之后（高地址端）
        if (v->start >= end) continue;
        // 没有重叠：VMA 完全在目标范围之前（低地址端）
        if (v->end <= start) continue;

        // 有重叠，处理四种情况
        if (start <= v->start && end >= v->end) {
            // 完全覆盖：删除整个 VMA
            list_del(&v->node);
            if (v->file) fileclose(v->file);
            kmem_cache_free(vma_cachep, v);
        } else if (v->start < start && v->end > end) {
            // 目标在 VMA 中间：分裂为前后两部分
            struct vma *new = kmem_cache_alloc(vma_cachep);
            if (new == 0) return 0;
            LIST_HEAD_INIT(new->node);
            new->start = end;
            new->end = v->end;
            new->vm_flags = v->vm_flags;
            new->file = v->file ? filedup(v->file) : 0;
            new->file_offset = v->file_offset + (end - v->start);
            new->vm_ops = v->vm_ops;
            new->vm_private_data = v->vm_private_data;
            v->end = start;
            list_add_tail(&new->node, &v->node);
        } else if (v->start < start) {
            // VMA 尾部重叠：缩短尾部
            v->end = start;
        } else {
            // VMA 头部重叠：缩短头部
            v->start = end;
        }
    }
    return 1;
}

void
vma_free_all(struct mm_struct *mm)
{
    struct vma *v, *n;
    list_for_each_entry_safe(v, n, &mm->mmap_list, node) {
        uint64 npages = (v->end - v->start) / PGSIZE;
        if (npages > 0 && mm->pagetable) {
            acquire(&mm->page_table_lock);
            uvmunmap(mm->pagetable, v->start, npages, 1);
            sfence_vma();
            release(&mm->page_table_lock);
        }
        if (v->file) fileclose(v->file);
        list_del(&v->node);
        kmem_cache_free(vma_cachep, v);
    }
}

int
vma_copy(struct mm_struct *dst, struct mm_struct *src)
{
    struct vma *v;
    list_for_each_entry(v, &src->mmap_list, node) {
        struct vma *new = kmem_cache_alloc(vma_cachep);
        if (new == 0) { vma_free_all(dst); return -1; }
        LIST_HEAD_INIT(new->node);
        new->start = v->start;
        new->end = v->end;
        new->vm_flags = v->vm_flags;
        new->file = v->file ? filedup(v->file) : 0;
        new->file_offset = v->file_offset;
        new->vm_ops = v->vm_ops;
        new->vm_private_data = v->vm_private_data;
        vma_insert(dst, new);
    }
    return 0;
}

// vma_split: 将 VMA v 在 [addr, addr+len) 处分裂
// 修改 v 为中间部分，创建前部和/或后部的副本
// 返回中间部分 VMA（权限可被修改）
struct vma *
vma_split(struct mm_struct *mm, struct vma *v, uint64 addr, uint64 len)
{
  uint64 end = addr + len;
  uint64 orig_start = v->start;
  uint64 orig_end = v->end;

  // 完全覆盖：不需要分裂
  if(addr <= orig_start && end >= orig_end)
    return v;

  // 前部保留 [orig_start, addr)
  if(addr > orig_start){
    struct vma *front = kmem_cache_alloc(vma_cachep);
    if(front == 0) return 0;
    LIST_HEAD_INIT(front->node);
    front->start = orig_start;
    front->end = addr;
    front->vm_flags = v->vm_flags;
    front->file = v->file ? filedup(v->file) : 0;
    front->file_offset = v->file_offset;
    front->vm_ops = v->vm_ops;
    front->vm_private_data = v->vm_private_data;
    vma_insert(mm, front);
  }

  // 后部保留 [end, orig_end)
  if(end < orig_end){
    struct vma *back = kmem_cache_alloc(vma_cachep);
    if(back == 0) return 0;
    LIST_HEAD_INIT(back->node);
    back->start = end;
    back->end = orig_end;
    back->vm_flags = v->vm_flags;
    back->file = v->file ? filedup(v->file) : 0;
    back->file_offset = v->file_offset + (end - orig_start);
    back->vm_ops = v->vm_ops;
    back->vm_private_data = v->vm_private_data;
    vma_insert(mm, back);
  }

  // 中间 [addr, end) — 修改原始 VMA
  v->start = addr;
  v->end = end;
  v->file_offset = v->file_offset + (addr - orig_start);

  return v;
}

// =========================
// 匿名映射 fault handler
// =========================
static uint64 anon_fault(struct vma *v, uint64 addr, int write) {
    uint64 mem = (uint64)kalloc();
    if(mem == 0) return 0;
    memset((void *)mem, 0, PGSIZE);
    acquire(&myproc()->mm->page_table_lock);
    uint64 result = vma_map_page(myproc()->mm, v, addr, mem);
    release(&myproc()->mm->page_table_lock);
    return result;
}

struct vm_operations anon_vm_ops = {
    .fault = anon_fault,
};

