// 分配并初始化 mm_struct
struct mm_struct *
mm_alloc(void)
{
    // Bypass slab allocator — use kalloc directly to isolate crash
    struct mm_struct *mm = (struct mm_struct *)kalloc();
    if(mm == 0)
        return 0;
    memset(mm, 0, PGSIZE);
    LIST_HEAD_INIT(mm->mmap_list);
    mm->map_count = 0;
    mm->mm_users = 1;
    mm->mm_count = 1;
    initsleeplock(&mm->mmap_lock, "mm_mmap");
    initlock(&mm->page_table_lock, "mm_pt");
    return mm;
}

// 增加 mm_users 引用（CLONE_VM 时用）
void
mm_grab(struct mm_struct *mm)
{
    __sync_fetch_and_add(&mm->mm_users, 1);
}

// 减少 mm_users，归零时释放地址空间和 mm_struct
void
mmput(struct mm_struct *mm)
{
    if(mm == 0)
        return;
    if(__sync_sub_and_fetch(&mm->mm_users, 1) > 0)
        return;
    vma_free_all(mm);
    mm_free_pagetable(mm);
    kmem_cache_free(mm_cachep, mm);
}

// 释放 mm_struct 的页表
void
mm_free_pagetable(struct mm_struct *mm)
{
    if(mm->pagetable == 0)
        return;
    uvmunmap(mm->pagetable, TRAMPOLINE, 1, 0);
    uvmunmap(mm->pagetable, TRAPFRAME, 1, 0);
    freewalk(mm->pagetable);
    mm->pagetable = 0;
}

#ifndef _XV6_FS_H_
#define _XV6_FS_H_

// On-disk file system format.
// Both the kernel and user programs use this header file.
#include "types.h"
#ifndef container_of
#define container_of(ptr, type, member) ((type *)((char *)(ptr) - offsetof(type, member)))
#endif

#define ROOTINO  1   // root i-number
#define BSIZE 1024  // block size

// Disk layout:
// [ boot block | super block | log | inode blocks |
//                                          free bit map | data blocks]
//
// mkfs computes the super block and builds an initial file system. The
// super block describes the disk layout:
struct xv6_sb_info {
  uint magic;        // Must be FSMAGIC
  uint size;         // Size of file system image (blocks)
  uint nblocks;      // Number of data blocks
  uint ninodes;      // Number of inodes.
  uint nlog;         // Number of log blocks
  uint logstart;     // Block number of first log block
  uint inodestart;   // Block number of first inode block
  uint bmapstart;    // Block number of first free map block
};

#define FSMAGIC 0x10203040

#define NDIRECT 12
#define NINDIRECT (BSIZE / sizeof(uint))
#define MAXFILE (NDIRECT + NINDIRECT)

// On-disk inode structure
struct xv6_dinode {
  short type;           // File type
  short major;          // Major device number (DT_CHR only)
  short minor;          // Minor device number (DT_CHR only)
  short nlink;          // Number of links to inode in file system
  uint size;            // Size of file (bytes)
  uint addrs[NDIRECT+1];   // Data block addresses
};

// Inodes per block.
#define IPB           (BSIZE / sizeof(struct xv6_dinode))

// Block containing inode i
#define IBLOCK(i, sb)     ((i) / IPB + sb.inodestart)

// Bitmap bits per block
#define BPB           (BSIZE*8)

// Block of free map containing bit for block b
#define BBLOCK(b, sb) ((b)/BPB + sb.bmapstart)

// Directory is a file containing a sequence of dirent structures.
#define XV6_NAME_LEN 14

// The name field may have XV6_NAME_LEN characters and not end in a NUL
// character.
struct xv6_dirent {
  ushort inum;
  char name[XV6_NAME_LEN] __attribute__((nonstring));
};

#define XV6_INODE(ip) container_of(ip, struct xv6_inode_info, vfs_inode)    // 得到xv6 fs的inode

#endif

#ifndef _PAGE_H_
#define _PAGE_H_

#include "types.h"
#include "memlayout.h"
#include "list.h"

struct kmem_cache;  // forward declaration for slab page union

// Per-physical-page metadata structure.
// One entry per page in the global mem_map[] array.
// sizeof(struct page) = 48 bytes on 64-bit.
// Union reuses refcount/order fields for slab metadata when PAGE_FLAG_SLAB is set.
struct page {
  uint64 flags;
  union {
    // Buddy page (PAGE_FLAG_SLAB not set)
    struct {
      uint32 refcount;       // page reference count (get_page/put_page)
      uint32 order;          // buddy allocation order
    };
    // Slab page (PAGE_FLAG_SLAB set)
    struct {
      uint16 inuse;          // number of allocated objects
      uint16 objects;        // total objects per page
      void *freelist;        // embedded free object list head
      struct kmem_cache *cache;  // owning cache backpointer
    };
  };
  struct list_head lru;      // buddy: free list / slab: partial+full list
};

// Global mem_map array: mem_map[pfn] = metadata for physical page at PFN pfn
extern struct page *mem_map;

// ---- Address conversion macros ----

// PFN is KERNBASE-relative so that mem_map[0] = page at KERNBASE (0x80000000).
// This keeps all indices within [0, (PHYSTOP-KERNBASE)/PGSIZE).
#define PFN_DOWN(pa)     (((uint64)(pa) - KERNBASE) >> 12)
#define PFN_UP(pa)       ((((uint64)(pa) - KERNBASE) + 0xFFF) >> 12)
#define PFN_PHYS(pfn)    (((uint64)(pfn) << 12) + KERNBASE)

#define pfn_to_page(pfn)  (&mem_map[(pfn)])
#define page_to_pfn(page) ((unsigned long)((page) - mem_map))
#define pa_to_page(pa)    pfn_to_page(PFN_DOWN(pa))
#define page_to_pa(page)  PFN_PHYS(page_to_pfn(page))
#define virt_to_page(kva) pfn_to_page(PFN_DOWN(kva))
#define page_to_virt(page) ((void *)PFN_PHYS(page_to_pfn(page)))

// ---- flags bit field definitions ----

#define PAGE_FLAG_ZONE_MASK  0x3UL       // bits [0-1]: zone ID (0=DMA, 1=NORMAL)
#define PAGE_FLAG_SLAB       (1UL << 2)  // owned by slab allocator
#define PAGE_FLAG_BUDDY      (1UL << 3)  // in buddy free list (free page)
#define PAGE_FLAG_RESERVED   (1UL << 4)  // reserved (kernel code, mem_map itself)
#define PAGE_FLAG_DIRTY      (1UL << 5)  // dirty page (for future page cache)
#define PAGE_FLAG_LOCKED     (1UL << 6)  // locked (for future IO)

// ---- flags manipulation macros ----

#define page_zone_id(page)     ((page)->flags & PAGE_FLAG_ZONE_MASK)
#define page_set_zone(page, z) \
  do { (page)->flags = ((page)->flags & ~PAGE_FLAG_ZONE_MASK) | (z); } while (0)

#define PageBuddy(page)      ((page)->flags & PAGE_FLAG_BUDDY)
#define SetPageBuddy(page)   ((page)->flags |= PAGE_FLAG_BUDDY)
#define ClearPageBuddy(page) ((page)->flags &= ~PAGE_FLAG_BUDDY)

#define PageReserved(page)    ((page)->flags & PAGE_FLAG_RESERVED)
#define SetPageReserved(page) ((page)->flags |= PAGE_FLAG_RESERVED)

#define PageSlab(page)       ((page)->flags & PAGE_FLAG_SLAB)
#define SetPageSlab(page)    ((page)->flags |= PAGE_FLAG_SLAB)
#define ClearPageSlab(page)  ((page)->flags &= ~PAGE_FLAG_SLAB)

// ---- Atomic reference count API ----

// Atomic increment reference count
static inline void get_page(struct page *page) {
  __sync_add_and_fetch(&page->refcount, 1);
}

// Atomic decrement reference count; free to buddy when reaching zero.
// Forward declaration: free_pages is defined in buddy.c
void free_pages(struct zone *z, void *pa, int order);
struct zone *pa_to_zone(uint64 pa);

static inline void put_page(struct page *page) {
  if (__sync_sub_and_fetch(&page->refcount, 1) == 0) {
    struct zone *z = pa_to_zone(page_to_pa(page));
    free_pages(z, (void *)page_to_pa(page), page->order);
  }
}

static inline int page_ref_count(struct page *page) {
  return page->refcount;
}

#endif // _PAGE_H_

