/* socket(2) - create a socket */
uint64
sys_socket(void)
{
  int domain, type, protocol;

  argint(0, &domain);
  argint(1, &type);
  argint(2, &protocol);

  int fd = socket_create(domain, type, protocol);
  return fd;
}

/* bind(2) - bind socket to address */
uint64
sys_bind(void)
{
  int fd;
  uint64 addr;
  int addrlen = sizeof(struct sockaddr_in);
  struct sockaddr sa;

  argint(0, &fd);
  argaddr(1, &addr);
  argint(2, &addrlen);

  socket_t *sock = socket_get(fd);
  if (sock == 0) return -ENOTSOCK;

  struct proc *p = myproc();
  if (copyin(p->mm->pagetable, (char *)&sa, addr, sizeof(sa)) < 0)
    return -EFAULT;

  int ret = socket_bind(sock, &sa, addrlen);
  if (ret < 0) return ret;

  /* Write back the sockaddr with actual port (helps programs that read
   * sin_port after bind with port 0, instead of calling getsockname) */
  if (copyout(p->mm->pagetable, addr, (char *)&sock->local_addr,
              sizeof(struct sockaddr_in)) < 0) {
    return -EFAULT;
  }

  return 0;
}

/* listen(2) - listen for connections */
uint64
sys_listen(void)
{
  int fd, backlog;

  argint(0, &fd);
  argint(1, &backlog);

  socket_t *sock = socket_get(fd);
  if (sock == 0) return -ENOTSOCK;

  int ret = socket_listen(sock, backlog);
  return ret;
}

/* accept(2) - accept a connection */
uint64
sys_accept(void)
{
  int fd;
  uint64 addr;
  uint64 addrlen;
  struct sockaddr sa;
  int sa_len = sizeof(struct sockaddr_in);

  argint(0, &fd);
  argaddr(1, &addr);
  argaddr(2, &addrlen);

  socket_t *sock = socket_get(fd);
  if (sock == 0) return -ENOTSOCK;

  int ret = socket_accept(sock, &sa, &sa_len);
  if (ret < 0) return ret;

  if (addr != 0) {
    struct proc *p = myproc();
    if (copyout(p->mm->pagetable, addr, (char *)&sa, sa_len) < 0)
      return -EFAULT;
  }

  if (addrlen != 0) {
    struct proc *p = myproc();
    if (copyout(p->mm->pagetable, addrlen, (char *)&sa_len, sizeof(sa_len)) < 0)
      return -EFAULT;
  }

  return ret;
}

/* accept4(2) - accept a connection on a socket (with flags) */
uint64
sys_accept4(void)
{
  int fd;
  uint64 addr;
  uint64 addrlen;
  int flags;
  struct sockaddr sa;
  int sa_len = sizeof(struct sockaddr_in);

  argint(0, &fd);
  argaddr(1, &addr);
  argaddr(2, &addrlen);
  argint(3, &flags);

  socket_t *sock = socket_get(fd);
  if (sock == 0) return -ENOTSOCK;

  int ret = socket_accept(sock, &sa, &sa_len);
  if (ret < 0) return ret;

  /* Apply SOCK_NONBLOCK flag to the new socket */
  if (flags & 0x800) {  /* SOCK_NONBLOCK */
    struct proc *p = myproc();
    if (ret >= 0 && ret < NOFILE) {
      struct file *nf = p->ft->ofile[ret];
      if (nf && nf->socket) {
        socket_t *ns = (socket_t *)nf->socket;
        ns->nonblocking = 1;
      }
    }
  }

  if (addr != 0) {
    struct proc *p = myproc();
    if (copyout(p->mm->pagetable, addr, (char *)&sa, sa_len) < 0)
      return -EFAULT;
  }

  if (addrlen != 0) {
    struct proc *p = myproc();
    if (copyout(p->mm->pagetable, addrlen, (char *)&sa_len, sizeof(sa_len)) < 0)
      return -EFAULT;
  }

  return ret;
}

