/* sendto(2) - send data to address */
uint64
sys_sendto(void)
{
  int fd;
  uint64 buf;
  int len, flags;
  uint64 dest_addr;
  int addrlen = sizeof(struct sockaddr_in);
  struct sockaddr sa;

  argint(0, &fd);
  argaddr(1, &buf);
  argint(2, &len);
  argint(3, &flags);
  argaddr(4, &dest_addr);
  argint(5, &addrlen);

  socket_t *sock = socket_get(fd);
  if (sock == 0) return -ENOTSOCK;

  if (len <= 0 || len > 65536)
    return -EINVAL;

  struct proc *p = myproc();
  char *kbuf = kmalloc(len);
  if (kbuf == 0) return -ENOMEM;

  if (copyin(p->mm->pagetable, kbuf, buf, len) < 0) {
    kfree(kbuf);
    return -EFAULT;
  }

  if (dest_addr != 0) {
    if (copyin(p->mm->pagetable, (char *)&sa, dest_addr, sizeof(sa)) < 0) {
      kfree(kbuf);
      return -EFAULT;
    }
  }

  int ret = socket_sendto(sock, kbuf, len, flags,
                          dest_addr ? &sa : 0, addrlen);
  kfree(kbuf);
  return ret;
}

