  argaddr(1, &buf);
  argint(2, &len);
  argint(3, &flags);
  argaddr(4, &src_addr);
  argaddr(5, &addrlen);

  socket_t *sock = socket_get(fd);
  if (sock == 0) return -ENOTSOCK;

  if (len <= 0 || len > 65536)
    return -EINVAL;

  char *kbuf = kmalloc(len);
  if (kbuf == 0) return -ENOMEM;

  int ret = socket_recvfrom(sock, kbuf, len, flags, &sa, &sa_len);
  if (ret < 0) {
    kfree(kbuf);
    return ret;
