  struct proc *p = myproc();
  if (copyout(p->mm->pagetable, buf, kbuf, ret) < 0) {
    kfree(kbuf);
    return -EFAULT;
  }

  if (src_addr != 0) {
    if (copyout(p->mm->pagetable, src_addr, (char *)&sa, sa_len) < 0) {
      kfree(kbuf);
      return -EFAULT;
    }
  }

  if (addrlen != 0) {
    if (copyout(p->mm->pagetable, addrlen, (char *)&sa_len, sizeof(sa_len)) < 0) {
      kfree(kbuf);
      return -EFAULT;
    }
  }

  kfree(kbuf);
  return ret;
