/* Loopback network interface */
static struct netif loopback_netif;

/* Loopback init callback (netif_init_fn)
 * With LWIP_NETIF_LOOPBACK=1, lwIP automatically sets
 * output = netif_loop_output_ipv4 in netif_loop_init().
 * We don't need to override it. */
static err_t
loopback_netif_init(struct netif *netif)
{
  /* Don't set output - let lwIP handle it */
  LWIP_UNUSED_ARG(netif);
  return ERR_OK;
}

/* Initialize loopback network interface */
void
loopback_init(void)
{
  ip4_addr_t ipaddr, netmask, gw;

  /* Parse IP addresses */
  ip4addr_aton(LOOPBACK_IP_ADDR, &ipaddr);
  ip4addr_aton(LOOPBACK_NETMASK, &netmask);
  ip4addr_aton(LOOPBACK_GW, &gw);

  /* Initialize lwIP */
  lwip_init();

  /* Add loopback interface */
  if (netif_add(&loopback_netif, &ipaddr, &netmask, &gw,
                NULL, loopback_netif_init, ip_input) == NULL) {
    panic("loopback_init: netif_add failed");
  }

  /* Set loopback as default interface */
  netif_set_default(&loopback_netif);

  /* Set loopback up */
  netif_set_up(&loopback_netif);
  netif_set_link_up(&loopback_netif);

  printf("loopback: initialized 127.0.0.1\n");
}

/* Poll loopback interface - process lwIP timers and loopback packets */
void
loopback_poll(void)
{
  static int polling = 0;
  if (polling)
    return;  /* prevent recursive reentry */
  polling = 1;
  /* Process any queued loopback packets.
   * Guard prevents the clock interrupt from calling netif_poll_all()
   * while we are mid-poll, which would corrupt the loopback queue. */
  lwip_op_begin();
  netif_poll(&loopback_netif);
  /* Check for lwIP timeouts (TCP retransmission, etc.) */
  sys_check_timeouts();
  lwip_op_end();
  polling = 0;
}

/* Safe poll from clock interrupt — skips if lwIP operation in progress */
void
loopback_poll_safe(void)
{
  if (lwip_op_guard == 0) {
    lwip_op_begin();
    netif_poll(&loopback_netif);
    sys_check_timeouts();
    lwip_op_end();
  }
}

/* Initialize the entire networking subsystem */
void
net_init(void)
{
  /* Initialize lwIP arch layer (locks, timers, memory) */
  lwip_arch_init();

  /* Initialize loopback interface (calls lwip_init internally) */
  loopback_init();

  /* Initialize socket subsystem */
  socket_init();

  printf("net: networking initialized\n");
}

