    lwip_arch_initialized = 1;
  }
}

/*
 * Get current time in milliseconds.
 * xv6 ticks increment at ~10Hz (100ms per tick).
 * Returns monotonic millisecond counter for lwIP timers.
 */
uint32_t
sys_now(void)
{
  return (uint32_t)(ticks * 100);
}

/*
 * Protect critical section — disable interrupts.
 * lwIP calls this before accessing shared data structures.
 * Returns opaque value for sys_arch_unprotect.
 */
unsigned int
sys_arch_protect(void)
{
  push_off();
  return 0;
}

/*
 * Unprotect critical section — re-enable interrupts.
 * Restores interrupt state saved by sys_arch_protect.
 */
void
sys_arch_unprotect(unsigned int pval)
{
  (void)pval;
  pop_off();
}

/*
 * Memory allocation using xv6 slab allocator (kmalloc).
 * kalloc() allocates whole pages; kmalloc() handles arbitrary sizes.
 */
void *
lwip_malloc(size_t size)
{
  if (size == 0)
    return (void *)0;
  void *p = kmalloc((uint64)size);
  return p;
}

/* Free memory allocated by lwip_malloc. */
void
lwip_free(void *ptr)
{
  if (ptr == 0) return;
  kfree(ptr);
}

/* Allocate zero-initialized memory. */
void *
lwip_calloc(size_t count, size_t size)
{
  return kcalloc((uint64)count, (uint64)size);
}

/*
 * malloc/free/calloc for lwIP when MEM_LIBC_MALLOC=1.
 * Uses our buddy allocator (kmalloc/kfree) which handles fragmentation
 * much better than lwIP's internal heap allocator.
 */
void *
malloc(size_t size)
{
  void *p = kmalloc((uint64)size);
  if (p == 0)
    printf("net-dbg: malloc(%d) failed!\n", (int)size);
  return p;
}

void
free(void *ptr)
{
  kfree(ptr);
}

void *
calloc(size_t count, size_t size)
{
  return kcalloc((uint64)count, (uint64)size);
}

/*
 * Reentrancy guard for timer-based lwIP polling.
 *
 * The clock interrupt may fire during an lwIP operation (e.g. sendto).
 * netif_poll_all() from the timer handler would corrupt lwIP state if
 * an operation is in progress.  lwip_op_begin/end bracket every lwIP
 * call so the timer can skip polling when it isn't safe.
 */
int lwip_op_guard = 0;

void
lwip_op_begin(void)
{
  lwip_op_guard++;
}

void
lwip_op_end(void)
{
  if (lwip_op_guard > 0)
    lwip_op_guard--;
}

