void main();
__attribute__ ((aligned (16))) char stack0[4096 * NCPU];

// entry.S passes hartid (a0) and dtb pointer (a1).
// dtb != 0 => booted from OpenSBI in S-mode
// dtb == 0 => booted from QEMU -bios none in M-mode
void
start(uint64 hartid, uint64 dtb)
{
  if (dtb >= 0x80000000) {   // OpenSBI passes DTB in RAM; -bios none gives 0
    // OpenSBI: already in S-mode, just enable interrupts and FPU
    w_sie(r_sie() | SIE_SEIE | SIE_STIE);
    w_sstatus(r_sstatus() | SSTATUS_SIE | SSTATUS_FS_INITIAL);
  } else {
    // M-mode boot: do full setup then switch to S-mode
    w_mstatus((r_mstatus() & ~MSTATUS_MPP_MASK) | MSTATUS_MPP_S | MSTATUS_FS_INITIAL);
    w_mepc((uint64)main);
    w_satp(0);
    w_medeleg(0xffff & ~(1 << 9));
    w_mideleg(0xffff);
    w_sie(r_sie() | SIE_SEIE | SIE_STIE);
    // PMP: allow S-mode full access
    w_pmpaddr0(0x3fffffffffffffULL >> 10);
    w_pmpcfg0(0xf);
    // enable SSTC for timer
    w_menvcfg(r_menvcfg() | (1L << 63));
    w_mcounteren(r_mcounteren() | 2);
    w_mie(r_mie() | MIE_STIE);
    // set first timer deadline
    w_stimecmp(r_time() + 1000000);
    w_tp(hartid);
    asm volatile("mret");
  }
  main();
}

