__attribute__ ((aligned (16))) char stack0[4096 * NCPU];
// Boot page tables are defined in entry.S .bss section (boot_pgd, boot_pud, boot_pmd, etc.)
// and set up with identity mapping before PG is enabled.

void
start(uint64 hartid, uint64 dtb)
{
  (void)hartid;
  (void)dtb;
  // LoongArch entry.S already set up DMW, stack, and cleared BSS.
  // Just enable interrupts and call main.
  w_sie(r_sie() | SIE_SEIE | SIE_STIE);
  w_sstatus(r_sstatus() | SSTATUS_SIE);
  main();
}

