struct k_sigaction {
  uintptr_t handler;               // offset 0
  uint64    flags;                 // offset 8 (low 32 bits = sa_flags)
  uint32    mask[2];               // offset 16 (sa_mask split into two 32-bit words)
  uintptr_t restorer;              // offset 24
};

