typedef struct {
  int si_signo;
  int si_errno;
  int si_code;
  union {
    int _pad[29];
    struct {
      int si_pid;
      int si_uid;
    } _kill;
  } _sifields;
} __attribute__((aligned(16))) siginfo_t;

/* sigcontext_t — 通用寄存器 + 浮点寄存器 */
typedef struct {
  uint64 sc_regs[32];
