} __attribute__((aligned(16))) sigcontext_t;

/* ucontext_t — 与 musl RISC-V 布局兼容 */
typedef struct ucontext {
  uint64        uc_flags;
  struct ucontext *uc_link;
  struct {
    void  *ss_sp;
    int    ss_flags;
    uint64 ss_size;
  } uc_stack;
  uint64        uc_sigmask[16];
  sigcontext_t  uc_mcontext;
} __attribute__((aligned(16))) ucontext_t;

/* sig_rt_frame_t — 信号帧，放置在用户栈上 */
typedef struct {
  uint64     flag;
  ucontext_t uc;
  siginfo_t  info;
  uint32     trampoline[2];
} __attribute__((aligned(16))) sig_rt_frame_t;

/* ---- 信号掩码工具函数 ---- */
static inline uint64 signal_mask_bit(int sig) {
  return (sig > 0 && sig < 64) ? (1ULL << sig) : 0;
}
static inline uint64 signal_mask_from_user(uint64 user_mask) {
  return user_mask << 1;
}
static inline uint64 signal_mask_to_user(uint64 kernel_mask) {
  return kernel_mask >> 1;
}

