int vfs_mount(int dev, int fs_type, char *target){
    int slot = -1;
    struct inode *mountpoint;
    if(target[0] == '/' && target[1] =='\0'){
        mountpoint = idup(&stub_root);
    }else{
        mountpoint = namei(target);
    }

    if(mountpoint == 0) return -1;

    // 找空槽并临时标记为已用，防止 I/O 期间被其他挂载抢占
    acquire(&mount_table.lock);
    for(int i=0;i<MAX_MOUNTS;i++){
        if(!mount_table.mounts[i].used){
            slot = i;
            mount_table.mounts[slot].used = 1;
            break;
        }
    }
    release(&mount_table.lock);
    if(slot == -1)
        return -1;

    // I/O 操作：不在 mount_table.lock 保护下执行
    struct super_block *sb = kalloc();
    sb->fs_type = fs_type;
    sb->dev = dev;
    if(fs_type == FS_XV6){
        if(xv6_fsinit(dev, sb) != 0){
            acquire(&mount_table.lock);
            mount_table.mounts[slot].used = 0;
            release(&mount_table.lock);
            iput(mountpoint);
            kfree_page(sb);
            return -1;
        }
    }else if(fs_type == FS_EXT4){
        if(lwext4_vfs_mount(dev, sb) != 0){
            acquire(&mount_table.lock);
            mount_table.mounts[slot].used = 0;
            release(&mount_table.lock);
            iput(mountpoint);
            kfree_page(sb);
            return -1;
        }
    }else{
        acquire(&mount_table.lock);
        mount_table.mounts[slot].used = 0;
        release(&mount_table.lock);
        iput(mountpoint);
        kfree_page(sb);
        return -1;
    }

    // 注册挂载信息
    acquire(&mount_table.lock);
    mount_table.mounts[slot].mountpoint = mountpoint;
    mount_table.mounts[slot].sb = sb;
    safestrcpy(mount_table.mounts[slot].path, target, 64);
    release(&mount_table.lock);
    return 0;
}

