int
main(void)
{
  int pid, wpid;

  if(open("console", O_RDWR) < 0){
    mknod("console", CONSOLE, 0);
    open("console", O_RDWR);
  }
  dup(0);  // stdout
  dup(0);  // stderr

  for(;;){
    printf("init: starting sh\n");
    pid = fork();
    if(pid < 0){
      printf("init: fork failed\n");
      exit(1);
    }
    if(pid == 0){
      exec("sh", argv);
      printf("init: exec sh failed\n");
      exit(1);
    }

    for(;;){
      // this call to wait() returns if the shell exits,
      // or if a parentless process exits.
      wpid = wait((int *) 0);
      if(wpid == pid){
        // the shell exited; restart it.
        break;
      } else if(wpid < 0){
        printf("init: wait returned an error\n");
        exit(1);
      } else {
        // it was a parentless process; do nothing.
      }
    }
  }
}

xv6_fsinit(int dev, struct super_block *sb) {
  struct xv6_sb_info *xv6_sb = kalloc();
  if(xv6_sb == 0){
    // panic("xv6_fsinit: failed to allocate memory");
    return -1;
  }
  xv6_readsb(dev, xv6_sb);
  if(xv6_sb->magic != FSMAGIC){
    kfree_page((void*)xv6_sb);
    return -1;  // wrong filesystem type, not a fatal error
  }
  xv6_initlog(dev, xv6_sb);
  sb->s_fs_info = xv6_sb;
  xv6_ireclaim(sb);
  sb->blocksize = BSIZE;
  // caller initiate the following variables
  // sb->dev = dev;
  // sb->fs_type = FS_XV6;
  sb->s_op = &xv6_sb_ops;
  sb->s_root = iget(dev, ROOTINO, sb);
  return 0;
}

// Zero a block.
static void
xv6_bzero(int dev, int bno)
{
  struct buf *bp;

  bp = bread(dev, bno);
  memset(bp->data, 0, BSIZE);
  xv6_log_write(bp);
  brelse(bp);
}

// Blocks.

// Allocate a zeroed disk block.
// returns 0 if out of disk space.
static uint
xv6_balloc(struct super_block *sb)
{
  struct xv6_sb_info *sbi = (struct xv6_sb_info *)sb->s_fs_info;
  struct xv6_sb_info xv6_sb = *sbi;
  int b, bi, m;
  struct buf *bp;
  int dev = sb->dev;

  bp = 0;
  for(b = 0; b < xv6_sb.size; b += BPB){
    bp = bread(dev, BBLOCK(b, xv6_sb));
    for(bi = 0; bi < BPB && b + bi < xv6_sb.size; bi++){
      m = 1 << (bi % 8);
      if((bp->data[bi/8] & m) == 0){  // Is block free?
        bp->data[bi/8] |= m;  // Mark block in use.
        xv6_log_write(bp);
        brelse(bp);
        xv6_bzero(dev, b + bi);
        return b + bi;
      }
    }
    brelse(bp);
  }
  printf("balloc: out of blocks\n");
  return 0;
}

