struct lwext4_vfs_blockdev {
    struct ext4_blockdev bd;
    struct ext4_blockdev_iface iface;
    uint8_t ph_bbuf[BSIZE];
    int dev;
    char dev_name[32];
};

static struct lwext4_vfs_blockdev vfs_bdev;

static int
blockdev_open(struct ext4_blockdev *bdev)
{
    (void)bdev;
    return EOK;
}

static int
blockdev_close(struct ext4_blockdev *bdev)
{
    (void)bdev;
    return EOK;
}

static int
blockdev_lock(struct ext4_blockdev *bdev)
{
    (void)bdev;
    return EOK;
}

static int
blockdev_unlock(struct ext4_blockdev *bdev)
{
    (void)bdev;
    return EOK;
}

static int
blockdev_read(struct ext4_blockdev *bdev, void *buf, uint64 blk_id, uint32 blk_cnt)
{
    struct lwext4_vfs_blockdev *vbdev = &vfs_bdev;
    int dev = vbdev->dev;
    uint64 _buf = (uint64)buf;

    for (uint32 i = 0; i < blk_cnt; i++) {
        struct buf *b = bread(dev, blk_id + i);
        memmove((void *)_buf, b->data, BSIZE);
        _buf += BSIZE;
        brelse(b);
    }
    return EOK;
}

static int
blockdev_write(struct ext4_blockdev *bdev, const void *buf, uint64 blk_id, uint32 blk_cnt)
{
    struct lwext4_vfs_blockdev *vbdev = &vfs_bdev;
    int dev = vbdev->dev;
    uint64 _buf = (uint64)buf;

    for (uint32 i = 0; i < blk_cnt; i++) {
        struct buf *b = bget(dev, blk_id + i);
        memmove(b->data, (void *)_buf, BSIZE);
        bwrite(b);
        _buf += BSIZE;
        brelse(b);
    }
    return EOK;
}

struct lwext4_vfs_blockdev *
lwext4_blockdev_init(int dev)
{
    struct lwext4_vfs_blockdev *vbdev = &vfs_bdev;
    struct ext4_blockdev *bd = &vbdev->bd;
    struct ext4_blockdev_iface *iface = &vbdev->iface;

    // Single global blockdev: if already configured for a different
    // device, reject to prevent corrupting the boot ext4 mount.
    // The mount test tries dev=2 which doesn't exist and would overwrite
    // the boot device configuration.
    if (strlen(vbdev->dev_name) > 0 && vbdev->dev != dev) {
        printf("lwext4_blockdev_init: already using %s, rejecting dev=%d\n",
               vbdev->dev_name, dev);
        return 0;
    }

    vbdev->dev = dev;

    bd->bdif = iface;
    bd->part_offset = 0;
    bd->part_size = (uint64)512 * 8 * 1024 * 1024;  // 4GB max

    iface->lock = blockdev_lock;
    iface->unlock = blockdev_unlock;
    iface->open = blockdev_open;
    iface->bread = blockdev_read;
    iface->bwrite = blockdev_write;
    iface->close = blockdev_close;
    iface->ph_bsize = BSIZE;
    iface->ph_bbuf = vbdev->ph_bbuf;
    iface->ph_bcnt = bd->part_size / BSIZE;

    // Generate unique device name
    if (dev == 0)
        safestrcpy(vbdev->dev_name, "virtio0", sizeof(vbdev->dev_name));
    else
        snprintf(vbdev->dev_name, sizeof(vbdev->dev_name), "virtio%d", dev);

    int status = ext4_device_register(&vbdev->bd, vbdev->dev_name);
    if (status != EOK) {
        printf("ext4_device_register failed: %d\n", status);
        return 0;
    }

    return vbdev;
}

void
lwext4_blockdev_destroy(void)
{
    struct lwext4_vfs_blockdev *vbdev = &vfs_bdev;
    if (strlen(vbdev->dev_name) > 0) {
        ext4_device_unregister(vbdev->dev_name);
        vbdev->dev_name[0] = '\0';
    }
}

